        ["2026-06-16-twitch-drop-now-live-get-the-cuddly-cotton-candy-grrgle-housing-decor--3281817486"] = {
            id = "2026-06-16-twitch-drop-now-live-get-the-cuddly-cotton-candy-grrgle-housing-decor--3281817486",
            post_key = "3281817486",
            title = "Twitch Drop Now Live! Get the Cuddly Cotton Candy Grrgle Housing Decor Item",
            category = "Blogs (US)",
            timestamp = 1781629648,
            url = "https://news.blizzard.com/en-us/article/24267734/twitch-drop-now-live-get-the-cuddly-cotton-candy-grrgle-housing-decor-item",
            content = {
            { type = "p", text = "Watch any eligible World of Warcraft stream on Twitch.tv from June 16 at 10:00 am PDT until July 14 at 10:00 am PDT to claim the Cuddly Cotton Candy Grrgle Housing decor item." },
            { type = "hr" },
            { type = "h3", text = "Eligibility" },
            { type = "p", text = "To participate, you must link your Twitch account by visiting https://account.battle.net/connections. If you have changed your password or made any changes to your Twitch or Battle.net account, you will have to relink your accounts. When you relink, there will be a 7-day cooldown before you can relink a new Twitch account. After you’ve claimed your rewards on Twitch, please make sure you’re logging into the Battle.net region you’d like to receive the drop(s) on, as the first region you log into will be where your items will be delivered. It can take up to 24 hours to receive your reward(s) in-game after claiming. Read our Frequently Asked Questions section for more information." },
            { type = "hr" },
            { type = "h3", text = "How do I Earn Twitch Drops?" },
            { type = "p", text = "Start Time: June 16, 10:00 am PDTEnd Time: July 14, 10:00 am PDT" },
            { type = "p", text = "Watch 4 hours of eligible World of Warcraft content while these Twitch Drops are active on any channel to earn the Cuddly Cotton Candy Grrgle Housing decor item." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-twitch-drop-now-live-get-the-cuddly-cotton-candy-grrgle-housing-decor--3281817486\\image-1.jpg" },
            { type = "p", text = "Players who have claimed this new item from the Twitch Drop will also be able to visit Dennia Silvertongue in Silvermoon City to purchase more copies of this adorable item. Additional copies can also be purchased from Tuuran in Stormwind and Gabbi in Orgrimmar (near the Trading Post)." },
            { type = "hr" },
            { type = "h3", text = "Frequently Asked Questions" },
            { type = "p", text = "Q. How do I link my battle.net and Twitch accounts? A. Sign into your Battle.net account at https://account.battle.net/connections and click the Connect link for Twitch, then follow the instructions to sign in and link your Twitch account to Battle.net." },
            { type = "p", text = "Q. What devices can I use to earn and claim drops? A. You can earn and claim drops using your PC/Mac web browser or on the Twitch app for Android or iOS. Twitch apps on game consoles, smart TVs, and other TV apps do not support drops." },
            { type = "p", text = "Q. Do I need to watch the same channel the entire time to earn my drops? A. You can earn progress towards a drop on any eligible channel in the World of Warcraft category on Twitch. You can, for example, watch half an hour on one channel and then switch to another channel without losing your progress. You cannot earn progress faster by watching more than one channel at a time." },
            { type = "p", text = "Q. Will I receive my drop rewards in-game automatically? A. To receive your rewards, you must claim the drop on the channel you’re watching or in the Drops Inventory menu on Twitch." },
            { type = "p", text = "Q. Do Twitch Drop rewards expire? A. Earned Twitch Drop rewards will expire seven (7) days after they’ve been claimed if a Battle.net account has not been linked." },
            { type = "p", text = "Q. As a streamer, how do I get Twitch Drops on my channel? A. All you need to do is ensure your Twitch and Battle.net accounts are linked and that you’ve opted into Drops (see Drops Streamer Home)." },
            { type = "p", text = "Q. What regions are eligible for these Twitch Drops? A. Participating regions include North America, Latin America, Europe, The Middle East, Africa, Japan, Taiwan, Southeast Asia, Australia, and New Zealand." },
            { type = "hr" },
            { type = "p", text = "Blizzard has the right to change, pause, or cancel this Twitch Drop and its terms if it cannot run as planned for any reason, including but not limited to technical issues or unexpected factors beyond Blizzard’s control." },
            { type = "p", text = "*Not available in World of Warcraft Classic® games. Requires World of Warcraft® Subscription or Game Time. Use and placement of decor items is limited to the Housing feature, which requires access to World of Warcraft®: Midnight." },
            },
        },
        ["2026-06-12-the-burning-crusade-hotfixes-updated-june-12-a1b072c8fc"] = {
            id = "2026-06-12-the-burning-crusade-hotfixes-updated-june-12-a1b072c8fc",
            post_key = "a1b072c8fc",
            title = "The Burning Crusade Hotfixes - Updated June 12",
            category = "The Burning Crusade Classic (US)",
            timestamp = 1781307460,
            url = "https://us.forums.blizzard.com/en/wow/t/2227871/1",
            content = {
            { type = "h2", text = "HOTFIXES" },
            { type = "h3", text = "June 12, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that caused Darkmoon Faire to not properly run on the first Friday of every month.", level = 0 },
            { type = "list_item", text = "An extra Darkmoon Faire holiday will be available in Terrokkar Forest starting June 15 until June 22.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 5, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "If multiple players use a Crystalforged Darkrune at Shartuul’s Transporter simultaneously, any player who does not take control of the Felguard will keep their Crystalforged Darkrune.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 2, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Following an Arena match, the user interface now displays the pre-match Matchmaking Ratings (MMR) for each team.", level = 1 },
            { type = "dev_note", text = "Our goal is to provide more information, so that players can better contextualize their changing MMR.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "April 1, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Significantly increased the amount of Honor earned in all battlegrounds.", level = 0 },
            { type = "h3", text = "February 20, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that was causing the Karazhan Chess Event to run much faster than intended, allowing Medivh to cheat more often than he should. Sneaky Medivh!", level = 0 },
            { type = "h3", text = "February 12, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Updated the Communal Flamewrought Keys to be usable by either faction if the character is Friendly with Honor Hold/Thrallmar.", level = 0 },
            { type = "list_item", text = "[With realm restarts] Fixed a bug that caused enemies to be less armored against physical attacks than intended.", level = 0 },
            { type = "h3", text = "February 4, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "The book ‘Soothsaying for Dummies’ has been re-enabled.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could prevent warlock players from being able to complete the quest “What is Love”.", level = 0 },
            { type = "list_item", text = "Fixed a bug where The Prophet Skeram would incorrectly purge buffs from players when transitioning between phases.", level = 0 },
            { type = "h3", text = "February 3, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player-characters who were incorrectly granted the 150 Epic riding skill have been reverted to riding skill 75.", level = 0 },
            { type = "h3", text = "January 27, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed a rare bug where characters who received a Level 58 Character Boost did not learn all their spells.", level = 0 },
            { type = "list_item", text = "Book “Soothsaying for Dummies”, used to re-choose profession specializations for Leatherworking and Engineering, has been temporarily disabled while we resolve an issue with it granting the wrong specialization.", level = 0 },
            { type = "dev_note", text = "We’re aiming to have the book reenabled in the not-too-distant future and will post a hotfix note when that happens.", level = 1 },
            { type = "list_item", text = "Fixed an issue where raid frames were not correctly displaying whether a player was in-range or not.", level = 0 },
            { type = "list_item", text = "Fixed an issue where pets with auto-cast spells would cause client performance to degrade over time.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused the pre-expansion event to disable briefly.", level = 0 },
            { type = "h3", text = "January 16, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue where Blackrock Spire only allowed 5 players to enter.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing the quest “The First and Last” from starting for eligible players.", level = 0 },
            { type = "list_item", text = "Cleansed Songflowers now apply their buff to the clicking player, not the player’s target.", level = 0 },
            { type = "list_item", text = "Paladins should now be able to learn Consecration from their trainer as intended.", level = 0 },
            { type = "list_item", text = "Shamans who were unable to learn Two-Handed Maces and Two-Handed Axes from the weapon trainer should again be able to.", level = 0 },
            { type = "dev_note", text = "Players may need to log out and back in to pick up this fix.", level = 1 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "The current active increase to Honor gains is now 150% (was a 100% bonus).", level = 1 },
            { type = "list_item", text = "Added level 51-60 versions of the “For Great Honor” (Horde) and “Concerted Effort” (Alliance) quests.", level = 1 },
            { type = "dev_note", text = "Soon after launching the Burning Crusade pre-expansion patch, we could see that PvP needed an additional increase in rate of gearing. These quests award 400 Honor (at level 60) when handed in, as well as experience for players from levels 51-59. These quests do not require Eye of the Storm, and their text will soon be updated to reflect that. When the Dark Portal opens, these quests will no longer be available, and the level 61-70 versions of these quests will become available.", level = 1 },
            { type = "h3", text = "January 14, 2025" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Restored character Boost services after a brief outage.", level = 0 },
            { type = "list_item", text = "Enabled Arena Skirmishes, as intended.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused Addons to be unintentionally throttled.", level = 0 },
            { type = "list_item", text = "Returned the Chronoboon Displacer to its adjusted cost of 1 gold and stack size of 10.", level = 0 },
            },
        },
