            { type = "p", text = "Watch any eligible World of Warcraft stream on Twitch.tv from June 16 at 10:00 am PDT until July 14 at 10:00 am PDT to claim the Cuddly Cotton Candy Grrgle Housing decor item." },
            { type = "p", text = "View Full Article" },
            },
        },
        ["2026-06-11-season-of-discovery-hotfixes-10-june-263f398a63"] = {
            id = "2026-06-11-season-of-discovery-hotfixes-10-june-263f398a63",
            post_key = "263f398a63",
            title = "Season of Discovery Hotfixes - 10 June",
            category = "Season of Discovery (EU)",
            timestamp = 1781136808,
            url = "https://eu.forums.blizzard.com/en/wow/t/495964/1",
            content = {
            { type = "h2", text = "HOTFIXES" },
            { type = "h3", text = "June 10, 2026" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Players may now disable or re-enable XP gains by speaking with Grendag Brightbeard in Ironforge in the Forlorn Cavern or the Valley of Strength in Orgrimmar.", level = 0 },
            { type = "dev_note", text = "There is a known issue where if you disable XP gains, this change does not persist after logging out and back in. We are temporarily removing the 1g cost for disabling and re-enabling XP gains while we investigate a fix for this issue.", level = 1 },
            { type = "h3", text = "June 10, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The incrementing player buff in Scarlet Enclave now increases by 5% every week (was every 2 weeks).", level = 0 },
            { type = "list_item", text = "Developer’s notes: In an effort to support players in Season of Discovery we’ve decided to advance the incrementing player buff in Scarlet Enclave to go up by 5% every week instead of every 2 weeks. Starting today, June 10, the buff will advance to 10%.", level = 1 },
            { type = "h3", text = "May 27, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Scarlet Enclave damage Rogue 2-piece set bonus will now behave consistently across Sinister Strike, Saber Slash, Mutilate, and Backstab.", level = 0 },
            { type = "list_item", text = "The Scarlet Enclave damage Warrior 6-piece set bonus will now correctly increase the damage of Off-Hand whirlwinds.", level = 0 },
            { type = "h3", text = "May 22, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "The Scarlet Enclave Protection Warrior Shoulders will no longer have the incorrect item category for one of the effects.", level = 1 },
            { type = "list_item", text = "The Scarlet Enclave Damage Warrior Feet will no longer have the incorrect item category for one of the effects.", level = 1 },
            { type = "h3", text = "May 16, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Items", level = 0 },
            { type = "list_item", text = "Spire of Sacrifice now prevents being healed by Chain Heal or Healing Rain and no longer damages the wielder with Healing Rain ticks.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "The Scarlet Enclave 4-piece healer set bonus will now correctly reduce incoming damage.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Carnage will no longer fall off prematurely when Cutthroat’s variant of Garrote is used.", level = 1 },
            { type = "h3", text = "May 9, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Fixed an issue where the Corrupted Ashbringer questline could get soft locked if you died while inside of Mount Hyjal between quests.", level = 0 },
            { type = "list_item", text = "Thisalee will allow you to go to Mount Hyjal after completing her quests, and will no longer allow you back into Mount Hyjal once you are finished there.", level = 1 },
            { type = "list_item", text = "If you complete the quest “Falling Into Place” and did not accept the follow-up quest “A Difficult Path” before the Will of the Ashbringer despawned, talk to Rix Xizzix in Booty Bay to get a replacement. How this Goblin got the Inert Ashbringer in his possession? We don’t know, but you’re just glad he found it!", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Sunlight will now correctly benefit from the Scarlet Enclave Shockadin 6-set bonus.", level = 1 },
            { type = "h3", text = "May 8, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Abandoned Experiment will no longer play its proc sound effect while you are at maximum stacks.", level = 0 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Leonid Barthalomew now temporarily exchanges the Scarlet Enclave Holy to Shockadin tier set (in addition to the Retribution to Shockadin set exchange). These will be removed from the vendor list on May 20.", level = 1 },
            { type = "list_item", text = "The Shockadin 6-piece set bonus has been adjusted – Now grants 8% spell power per stack of Holy Power consumed while using a one-handed weapon, and 18% spell power per stack of Holy Power consumed when using a 2-handed weapon (was 15% spell power per stack of Holy Power consumed).", level = 1 },
            { type = "list_item", text = "Enchanting", level = 0 },
            { type = "list_item", text = "Access to the New Avalon Mage Tower now requires Enchanting 280 (was 300), matching the requirements of the rest of the puzzle.", level = 1 },
            { type = "h3", text = "May 6, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Fixed an issue that prevented players who have completed the quest “Decapitation Strike” from being able to view a certain roleplay event that starts at Light’s Hope Chapel when another player turns in the quest “Fall of the Grand Crusader”.", level = 0 },
            { type = "list_item", text = "The proc from Mirage will no longer cause the master to stand up when their Mirage casts Arcane Explosion.", level = 0 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Caldoran now drops 1 additional non-tier token piece of loot.", level = 1 },
            { type = "list_item", text = "Lilian Voss now drops a Crusader’s Chalice.", level = 1 },
            { type = "list_item", text = "The first boss you loot after Balnazzar now drops a Jostled Chalice Fragment once per week.", level = 1 },
            { type = "dev_note", text = "This means if you did the raid in a linear manner, looting Beatrix would grant you a Jostled Chalice Fragment. But if you forgot to loot her, joined the raid late, or joined a pick up group that was already in progress, the first boss you loot will grant you a Jostled Chalice Fragment.", level = 1 },
            { type = "h3", text = "May 5, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The buffs granted from Corrupted Ashbringer are no longer Magic effects.", level = 0 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "The Scarlet Enclave Protection 6-set bonus now correctly also allows the use of Avenging Wrath while under the effects of Forbearance.", level = 1 },
            { type = "h3", text = "May 2, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Elemental Invasions now spawn every 1-2 hours (was every 24-48 hours).", level = 0 },
            { type = "list_item", text = "The Grand Arcanist and Grand Sorcerer enchants now additionally grant Healing Power equal to the same amount of spell power.", level = 0 },
            { type = "list_item", text = "The Grand Arcanist and Grand Sorcerer enchants now have a 0.1 second cooldown on them to prevent players from getting multiple procs of the mana restoration effect on a singular spell cast.", level = 0 },
            { type = "list_item", text = "The Grand Arcanist and Grand Sorcerer enchants can now proc from non-periodic healing spells that heal during combat.", level = 0 },
            { type = "list_item", text = "The Mirage summoned from the Mirage, Rod of Illusion will no longer attempt to melee attack under certain conditions.", level = 0 },
            { type = "list_item", text = "Immolation Traps will no longer Melee during the Alexei the Beastlord encounter.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "The Naxxramas damage 4-piece bonus will now correctly apply to and activate the Corruption applied by the Scarlet Enclave tank 2-piece bonus.", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Tank 4-piece bonus now correctly applies its heal from Corruption ticks off the instant tick from the Naxxramas damage 4-piece bonus.", level = 2 },
            { type = "h3", text = "April 30, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Lucky Doubloon now has a small 1.5 second cooldown, even if you flip heads to clear the cooldown on the item. This is to prevent it from being flipped multiple times unintentionally.", level = 0 },
            { type = "list_item", text = "The Quartermaster’s Crate is now provided upon acceptance of “Prove Your Worth” from Bryon Steelblade.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Paladin", level = 1 },
            { type = "list_item", text = "The Avenging Shield buff granted from the Scarlet Enclave 6-piece set bonus for Protection Paladins correctly lasts the same duration as Avenging Wrath.", level = 2 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "There are now 3 Torn Pages containing Torn Diary Pages in them in Scarlet Enclave. These should be lootable by and tradable to players who were present for the Reborn Council encounter. Torn Pages should no longer disappear if there is a soft reset after the Reborn Council but before Lillian Voss.", level = 1 },
            { type = "list_item", text = "Berserk Timers for all bosses, except Caldoran, have been increased to 10 minutes.", level = 1 },
            { type = "list_item", text = "Caldoran will now Berserk 6 minutes after Phase 2 begins (was 5 minutes after).", level = 1 },
            { type = "list_item", text = "The aggro radiuses of the Reborn Council have been lowered to allow for easier prepositioning before pulling the boss.", level = 1 },
            { type = "h3", text = "April 28, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Caladboulder will now lose 1 durability every time the Chance on Hit stun proc activates.", level = 0 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "There are now three Torn Pages for Putress’ Diary per Scarlet Enclave instance, as intended (was incorrectly 1).", level = 1 },
            { type = "list_item", text = "The Hoard of the Pirate Lord containing the Lucky Doubloon will now require you to kil Mason the Echo before being able to loot it (was: required killing Balnazzar before looting, and was also using his tap list - creating issues for Master Looters and not having a chest if a soft reset happened between Balnazzar and Mason).", level = 1 },
            { type = "list_item", text = "The Hoard of the Pirate Lord will no longer despawn if there is a soft reset done on the instance after Balnazzar.", level = 1 },
            { type = "list_item", text = "The Hoard of the Pirate Lord will no longer despawn if the chest is left open for too long.", level = 1 },
            { type = "list_item", text = "Caldoran", level = 1 },
            { type = "list_item", text = "Enemies will no longer show the Panic debuff while they are dead.", level = 2 },
            { type = "list_item", text = "Enemies will no longer ignore Panic if they have Curse of Recklessness active when it is cast.", level = 2 },
            { type = "list_item", text = "Enemies will (hopefully) no longer stay alive while at 1 health.", level = 2 },
            { type = "list_item", text = "Lilian Voss", level = 1 },
            { type = "list_item", text = "Ignite has had its initial damage reduced and the scaling amount reduced.", level = 2 },
            { type = "h3", text = "April 24, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Experiment-800M will now correctly only activate its On Use splash damage off of Ranged attacks that involve the Weapon itself. E.g. not Thunder Clap or Shuriken Toss but will activate off Quick Shot and Between the Eyes.", level = 0 },
            { type = "list_item", text = "Transmute Mithril to Truesilver and Transmute Iron to Gold now benefits from Transmutation Mastery.", level = 0 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Caldoran", level = 1 },
            { type = "list_item", text = "Divine Conflagration’s ground effect no longer displays a duration while inside.", level = 2 },
            { type = "list_item", text = "Divine Conflagration will now show on the adds so players know when they are inside of the area.", level = 2 },
            { type = "list_item", text = "Adds will no longer fail to die when they hit 1 health.", level = 2 },
            { type = "list_item", text = "Wake of Ashes has had its windup animation changed to be slightly more distinct compared to his other attacks.", level = 2 },
            { type = "list_item", text = "Adds will no longer fail to be feared between phases if they are crowd controlled.", level = 2 },
            { type = "h3", text = "April 23, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Druid", level = 1 },
            { type = "list_item", text = "The Scarlet Enclave Restoration 6-piece set bonus now has a 100% chance to spread your Rejuvenation (was 50%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 1 },
            { type = "list_item", text = "Increased the benefit of Shock and Awe so that dealing Holy Shock damage grants you 200% of your Intellect as Spell Damage, and reduces the threat you generate by 30% for 1 minute, and you are empowered with Sunlight for 10 seconds, causing Divine Storm, Crusader Strike, and melee attacks to deal bonus Holy damage equal to 100% of your holy spell power.", level = 2 },
            { type = "list_item", text = "The Wrath rune now benefits Sunlight.", level = 2 },
            { type = "list_item", text = "Soul of the Sealbearer reduces the damage dealt by Sunlight.", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Holy 2-piece bonus has changed to: grants 20% Spell Haste and causes your next 5 Divine Light, Holy Light, Flash of Light, or Holy Shock spells to have a 0.5 second reduced global cooldown, lasting 30 seconds (was 20% Spell Haste for 1 minute).", level = 2 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "The Scarlet Enclave Healer Tier set 2-piece now also reduces the cooldown on Power Word: Barrier by 30 seconds.", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Healer Tier set 4-piece now also increases the healing done by Serendipity empowered spells by 10% per stack of Serendipity spent.", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Healer Tier set 6-piece no longer works with Power Infusion.", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Healer Tier set 6-piece now also increases the healing of Penance and Circle of Healing by 25%.", level = 2 },
            { type = "list_item", text = "Warrior", level = 1 },
            { type = "list_item", text = "The Scarlet Enclave Protection Tier set 6-piece bonus will no longer incorrectly be consumed by strikes from Retaliation.", level = 2 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Unstable Concoction can no longer crit, no longer benefits from the target’s spell power, and no longer benefits from the caster’s % damage modifiers.", level = 1 },
            { type = "h3", text = "April 21, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "[ With realm restarts ] The Portable Cannon item will now deal its damage to targets even if they are Immune to the stun portion of the effect.", level = 0 },
            { type = "list_item", text = "The Vanquished Tentacle of C’thun and the Eye of Mar’li have been added to the list of items that cannot be used while in a neutral area like Cenarion Hold or Light’s Hope Chapel.", level = 0 },
            { type = "list_item", text = "The Scarlet Base Camp is now considered a neutral area where certain effects and spells, like Homunculi, cannot be used.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Hunter", level = 1 },
            { type = "list_item", text = "Carve will now benefit from effects that reference a “Strike” type ability (was not a Strike previously).", level = 2 },
            { type = "list_item", text = "Mage", level = 1 },
            { type = "list_item", text = "Deep Freeze will now correctly have its damage increased by 20% per stack of Glaciate (was 10% per stack).", level = 2 },
            { type = "list_item", text = "The Balefire Bolt debuff that increases the damage of Balefire Bolt by 25% per stack now also increases the damage of your Pyroblast by the same percent**.**", level = 2 },
            { type = "list_item", text = "Paladin", level = 1 },
            { type = "list_item", text = "Increases and decreases to Judgement will no longer affect Seal of Command.", level = 2 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "Vampiric Embrace will no longer be subject to the healing reduction players experience in PvP.", level = 2 },
            { type = "dev_note", text = "This was making Vampiric Embrace much weaker than intended, due to the initial spell dealing less damage and then being reduced further by the healing reduction.", level = 2 },
            { type = "list_item", text = "Rogue", level = 1 },
            { type = "list_item", text = "The base physical damage reduction from Just a Flesh Wound has been reduced to 20% (was 30%).", level = 2 },
            { type = "dev_note", text = "We’ve lowered the flat damage reduction portion of Just a Flesh Wound. When this was increased (when the defense scaling was introduced), this number being 30% was used to help bridge the shift from tanking in damage gear to tanking in tank gear. We feel enough time has passed to lower this number, as players have had adequate access to gear they could swap over to or get a new set of if they had geared for damage.", level = 2 },
            { type = "list_item", text = "Shaman", level = 1 },
            { type = "list_item", text = "The Scarlet Enclave Elemental 2-piece set bonus will no longer chain to other targets while Burn is engraved (was casting a Flame Shock tick that chained even to targets that didn’t have a Flame Shock active and also chaining multiple times across targets if Chain Lightning was the triggering spell).", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Elemental 2-piece set bonus will now correctly mirror the damage of a Flame Shock tick (was treating some bonuses as multiplicative instead of additive, resulting in more damage than a normal Flame Shock tick).", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Elemental 2-piece set bonus will no longer play a Flame Shock animation from the caster whenever it activates.", level = 2 },
            { type = "list_item", text = "The Scarlet Enclave Elemental 2-piece set bonus will now correctly strike targets with an instant tick of Flame Shock that are out of normal Flame Shock range of 20 yards (was: enemies needed to be within the normal Flame Shock).", level = 2 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "Shadow Bolt Volley now causes Shadow Bolt to deal 30% reduced damage (was 5%).", level = 2 },
            { type = "list_item", text = "Shadow Bolt Volley no longer deals reduced damage if there is only one target that is struck by your Shadow Bolt cast (was: always deals reduced damage while the rune is engraved).", level = 2 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Mason the Echo", level = 1 },
            { type = "list_item", text = "The Berserk timer has been increased to 7 minutes.", level = 2 },
            { type = "list_item", text = "Scarlet Cannonballs are now properly removed when the boss leashes and resets.", level = 2 },
            { type = "list_item", text = "Alexei the Beastlord", level = 1 },
            { type = "list_item", text = "Enervate and Enkindle have had their periodic damage reduced slightly.", level = 2 },
            { type = "list_item", text = "The spell visuals for Wild Fissure have been improved.", level = 2 },
            { type = "list_item", text = "Reborn Council", level = 1 },
            { type = "list_item", text = "Blast Wave’s vertical arc from the knockback has been lessened.", level = 2 },
            { type = "h3", text = "April 17, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The effects of the Conundrum wand will no longer occasionally fall off.", level = 0 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Explosive Shot now correctly benefits from the Moral Shots talent and deals increased critical strike damage.", level = 1 },
            { type = "list_item", text = "Explosive Shot will not benefit from the Scarlet Enclave 2-set Ranged bonus.", level = 1 },
            { type = "list_item", text = "Explosive Shot’s damage over time portion can no longer return a Miss, but the initial application of Explosive Shot still can.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The Fallen Regality set will now correctly restore energy to the Rogue after casting Crimson Tempest.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Enhancement Tier 3 pieces can now also be traded for Elemental Tier 3 pieces until April 28.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "The Scarlet Enclave Protection Warrior 2-set bonus has had its damage on Shockwave increased to 60% (was 35).", level = 1 },
            { type = "list_item", text = "Warriors in Season of Discovery now have an additional 10% reduction to damage taken while in Defensive Stance.", level = 1 },
            { type = "list_item", text = "Threat generated by the Furious Thunder Rune increased to 75% (was 50%).", level = 1 },
            { type = "list_item", text = "The attack power ratio of Thunder Clap in Season of Discovery has been increased to 7% (was 5%).", level = 1 },
            { type = "list_item", text = "Thunder Clap now uses your Ranged hit chance to land and can return a Miss (was Spell hit chance and can return a Resist).", level = 1 },
            { type = "list_item", text = "Engraving Defense Specialization onto your Ring will grant your Thunder Clap 3% increased chance to hit, to make up for the fact that Weapon Skill does not affect it normally.", level = 1 },
            { type = "list_item", text = "Thunder Clap is now capable of landing a critical strike. Because of this, Thunder Clap now benefits from Impale.", level = 1 },
            { type = "dev_note", text = "Just to be clear and set expectations with interactions, Thunder Clap will not apply Deep Wounds upon landing a Critical Strike.", level = 2 },
            { type = "list_item", text = "Devastate’s damage per stack of Sunder has been increased to 15% (was 10%).", level = 1 },
            { type = "dev_note", text = "Currently Devastate is weaker than a basic attack, this should bring it more in line as a filler without being overtaken by Thunder Clap as a way to deal damage.", level = 2 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Scarlet Arrow, Multi-Shot, Aimed Shot, Holy Cleave, Ignite Flesh, Wild Fissure, Peeled Secrets, and Unstable Concoction will no longer deal damage to pets.", level = 1 },
            { type = "list_item", text = "Balnazzar", level = 1 },
            { type = "list_item", text = "You can no longer release during the ending RP of the Balnazzar encounter.", level = 2 },
            { type = "list_item", text = "Players who are dead will now be teleported with the rest of the raid when the RP at the end of the Balnazzar encounter finishes.", level = 2 },
            { type = "list_item", text = "Beatrix’s portion of the RP before the Prison should now be visible to players even if they are farther away.", level = 2 },
            { type = "list_item", text = "Balnazzar’s encounter should now always result in a lootable chest even if everyone dies during the ending of the encounter.", level = 2 },
            { type = "list_item", text = "If there are remaining Lightbearers at the end of the fight, they will now correctly despawn.", level = 2 },
            { type = "h3", text = "April 15, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Exquisite Spices from the Scarlet Junkbox are no longer Bind-on-Pickup. This does not retroactively apply to previously obtained Exquisite Spices.", level = 0 },
            { type = "list_item", text = "Condemnation will now activate its effect when abilities such as Insect Swarm and Shadow Word: Pain are cast.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "Spirit of Redemption will no longer prevent the use of Darkmoon Card: Twisting Nether.", level = 2 },
            { type = "list_item", text = "Shaman", level = 1 },
            { type = "list_item", text = "For players to adjust to the set bonus change, the Naxxramas Tier vendor for Shamans will now offer an exchange from the Enhancement Tier to the Tank Tier. This is a one-way exchange and will no longer be available after April 28.", level = 2 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Alexei the Beastlord", level = 1 },
            { type = "list_item", text = "Enervate and Enkindle can no longer target pets.", level = 2 },
            { type = "list_item", text = "Enkindle and Enervate now ignore line-of-sight.", level = 2 },
            { type = "list_item", text = "Balnazzar", level = 1 },
            { type = "list_item", text = "Sleep now grants players damage immunity.", level = 2 },
            { type = "list_item", text = "The carrier of Carrion Swarm now has a visible debuff.", level = 2 },
            { type = "list_item", text = "Lillian Voss", level = 1 },
            { type = "list_item", text = "Ambition no longer increases her casting speed.", level = 2 },
            { type = "list_item", text = "Immolation Aura no longer targets pets.", level = 2 },
            { type = "list_item", text = "Intoxicating Venom should no longer dispel anything other than itself.", level = 2 },
            { type = "list_item", text = "Putress’ Poison Bolts during berserk now ignore line-of-sight.", level = 2 },
            { type = "h3", text = "April 14, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Sunlight sword no longer scales with spell power. It now inflicts physical damage (was holy damage).", level = 0 },
            { type = "list_item", text = "Khonsu’s auto attack damage can no longer be mitigated by armor and deals less base damage.", level = 0 },
            { type = "list_item", text = "Dedicated Sunglasses can now be toggled on and off with the /flex emote.", level = 0 },
            { type = "list_item", text = "Players who have lost their Dedication effect but carry a Linkue Combatant Icon will have their aura restored the next time they use the item.", level = 0 },
            { type = "list_item", text = "A random Darkmoon Faire card will now appear in Damaged Undermine Supply Crates and Wartorn Undermine Supply Crates.", level = 0 },
            { type = "list_item", text = "[ With realm restarts ] The Scarlet Junkbox from the weekly quest in New Avalon will now always contain only one Jostled Chalice Fragment (was a chance at multiples). The amount of Fragments needed to complete a Crusader’s Chalice has been reduced to 3 (was 6).", level = 0 },
            { type = "dev_note", text = "This should allow players a more consistent way to get Tier Tokens and pieces outside of the raid every 3 weeks.", level = 1 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Druid", level = 1 },
            { type = "list_item", text = "The Restoration Druid T3 2-piece bonus will now correctly allow multiple Druids with the set bonus to cause the effect on the same target.", level = 2 },
            { type = "list_item", text = "Paladin", level = 1 },
            { type = "list_item", text = "Hammer of the Righteous now deals 4x weapon dps (was 3x).", level = 2 },
            { type = "list_item", text = "Hammer of the Righteous now strikes 3 additional targets (was 2).", level = 2 },
            { type = "list_item", text = "Avenger’s Shield now benefits from the Precision talent for its hit chance.", level = 2 },
            { type = "list_item", text = "Avenger’s Shield now gains 3% chance to hit when Defense Specialization is engraved.", level = 2 },
            { type = "dev_note", text = "This is to counter the fact there is no other way to add additional hit to it through Weapon Skill.", level = 3 },
            { type = "list_item", text = "Shaman", level = 1 },
            { type = "list_item", text = "[ With realm restarts ] The T3 Enhancement Shaman 2-piece bonus now requires the player to have the Static Shock rune engraved. The tooltip will be updated at a later date.", level = 2 },
            { type = "list_item", text = "Blackrock Depths", level = 0 },
            { type = "list_item", text = "Ever After can now be completed in group sizes larger than two players.", level = 1 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Caldoran can no longer have his power drained or burned.", level = 1 },
            { type = "list_item", text = "Herod can no longer have his power drained or burned.", level = 1 },
            { type = "list_item", text = "Fixed an issue that allowed Solistrasza’s “Cremation” spell to be interrupted.", level = 1 },
            { type = "list_item", text = "Fixed an issue that would cause Lightgorged Whelps to erroneously trigger Solistrasza’s encounter record.", level = 1 },
            { type = "list_item", text = "Balnazzar’s Screeching Fear cast time increased to 2.5 seconds.", level = 1 },
            { type = "list_item", text = "Balnazzar will now berserk at 10 minutes.", level = 1 },
            { type = "list_item", text = "Sleep is no longer able to be canceled or removed early.", level = 1 },
            { type = "list_item", text = "The patrol after the Reborn Council should no longer pull through the wall.", level = 1 },
            { type = "list_item", text = "Beatrix and add health reduced by 25%.", level = 1 },
            { type = "list_item", text = "Beatrix will only spawn two sets of adds and perform two class calls before becoming active (down from 3 and 3)", level = 1 },
            { type = "list_item", text = "Beatrix enrage timer increased to 10 minutes.", level = 1 },
            { type = "list_item", text = "Ranged adds will run in a little further towards players after spawning before casting ranged spells", level = 1 },
            { type = "list_item", text = "Stock Break will now properly grant damage immunity during its duration", level = 1 },
            { type = "list_item", text = "Rose’s Thorn timer has been adjusted to better alternate and not overlap with Stock Break", level = 1 },
            { type = "list_item", text = "Rose’s Thorn Charge speed is slightly slower", level = 1 },
            { type = "list_item", text = "Beatrix should not melee during or immediately after Rose’s Thorn", level = 1 },
            { type = "list_item", text = "Rose’s Thorn, Confession, and Scarlet Arrows damage reduced.", level = 1 },
            { type = "h3", text = "April 11, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Fizzlefuse will now sell ammunition to players right away.", level = 0 },
            { type = "list_item", text = "Fixed an issue that sometimes caused the quest “Loss” in Eastern Plaguelands to stall.", level = 0 },
            { type = "list_item", text = "World Buff consumables now cost 5 Commendations each (was 25).", level = 0 },
            { type = "list_item", text = "Fixed an issue causing the locked doors in New Avalon to not be able to be opened when players are wearing the Scarlet Disguise and have the Scarlet Key in their inventory.", level = 0 },
            { type = "list_item", text = "Consumable Tinkerboxes can now be activated while Shapeshifted.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "Vampiric Embrace will now heal the priest for twice as much as they heal others.", level = 2 },
            { type = "list_item", text = "Vampiric Embrace in Season of Discovery can no longer roll a critical result.", level = 2 },
            { type = "list_item", text = "Rogue", level = 1 },
            { type = "list_item", text = "The Tank Rogue Tier-2.5 2-piece bonus will no longer sometimes prevent Blade Flurry from activating. Strikes of the Sinister now has a lower priority than Blade Flurry.", level = 2 },
            { type = "list_item", text = "Karazhan Crypts", level = 0 },
            { type = "list_item", text = "The Burning Webs from the Creeping Malison encounter in Karazhan Crypts will no longer hit players in Kharon’s room after the encounter is completed.", level = 1 },
            { type = "list_item", text = "Naxxramas", level = 0 },
            { type = "list_item", text = "The Unholy Weapon enemies in Naxxramas will no longer gain twice the % damage increase from Authority of the Frozen Wastes.", level = 1 },
            { type = "list_item", text = "Scarlet Enclave", level = 0 },
            { type = "list_item", text = "Health values for non-boss enemies have been significantly reduced across the entire raid.", level = 1 },
            { type = "list_item", text = "The locations of the Mage Tower and Guard Tower lieutenants before the Beatrix encounter now spawn at the base of their towers.", level = 1 },
            { type = "list_item", text = "Removed some of the Artillery enemies around the Blacksmith.", level = 1 },
            { type = "list_item", text = "Beatrix", level = 1 },
            { type = "list_item", text = "The utility, healing, and disruption spells used by Beatrix’s troops have either been cut or reduced in effectiveness. Affected spells include Concussion Shot, Disarm, Shield Slam stun, and Polymorph.", level = 2 },
            { type = "list_item", text = "Beatrix’s health reduced by 5%.", level = 2 },
            { type = "list_item", text = "Adjusted the timing and overlap of her Class Call spells. For example, there are now 4 waves of Scarlet Infantry during Scarlet Phalanx (was 6), 4 waves of Scarlet Cavalry during Thundering Hooves (was 5), and slightly less overlap between Mortar Combat from the Artillery into the Meteor from Scarlet Mages.", level = 2 },
            { type = "list_item", text = "Adjusted the Out of Bounds triggers that could result in a Scarlet Phalanx (Infantry Class Call) gap forcing players to walk out of bounds and take unnecessary damage.", level = 2 },
            { type = "list_item", text = "Caldoran", level = 1 },
            { type = "list_item", text = "Fixed an issue that could result in Caldoran becoming stuck if players entered the Radiant Portal after resurrecting.", level = 2 },
            { type = "list_item", text = "Solistrasza", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused “Aberrant Bloat” to have no spell icon.", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Solistrasza’s “Radiant Light” to erroneously display.", level = 2 },
            { type = "h3", text = "April 7, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "World buffs and world buff consumables no longer work in Battlegrounds.", level = 0 },
            { type = "h3", text = "April 3, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Developers’ note: The changes below went live with this week’s realm restarts.", level = 0 },
            { type = "list_item", text = "The stun during the Kel’thuzad encounter on Hard Mode 4 can no longer be immuned.", level = 0 },
            { type = "list_item", text = "Kel’thuzad now correctly comes back up with full health regardless of debuffs placed on him during the transition phase.", level = 0 },
            { type = "h3", text = "March 20, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "The (up to) 50% health increase in Battlegrounds has been removed.", level = 1 },
            { type = "list_item", text = "The global Damage Reduction to spells in PvP has been increased to 50% Physical/60% Magic reductions (was 25% Physical/40% Magic reductions).", level = 1 },
            { type = "dev_note", text = "Players should now have 50% more effective health in PvP against both Physical and Magical damage in the open world, and PvP in Battlegrounds should feel unchanged.", level = 2 },
            { type = "h3", text = "March 17, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Changing difficulties or activating and deactivating orbs in Naxxramas will no longer interrupt the drinking or eating of players in the raid that aren’t channeling on the orb or conduit.", level = 0 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Enchanted Flare will no longer disrupt allied players’ channeled effects.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Rampage now increases attack power by 15% (was 10%).", level = 1 },
            { type = "list_item", text = "Rampage cooldown decreased to 90 seconds (was 120 seconds).", level = 1 },
            { type = "list_item", text = "Removing the Protection Warrior T3 4-piece set bonus will now correctly remove the cooldowns it effects.", level = 1 },
            { type = "h3", text = "March 12, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Pressing Starfall a second time after it has been cast, and the Global Cooldown is finished, now cancels Starfall.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Presence of Mind will no longer unexpectedly stay on the Mage under certain circumstances.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The Elemental Shaman Tier-2 4-piece set bonus now removes your Loyal Beta when the set bonus is removed or broken.", level = 1 },
            { type = "h3", text = "March 11, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Seal of the Dawn item now stops increasing at Rank 7.", level = 0 },
            { type = "dev_note", text = "This means there is no increase this week, and you will not have to spend Remnants of Valor if you are already at Rank 7. If you have additional Remnants of Valor, you can spend them on Argent Dawn Valor Tokens or send them to alts via the mailbox to upgrade your alts’ Seal of the Dawn or increase their Argent Dawn reputation through Argent Dawn Valor Tokens.", level = 1 },
            { type = "h3", text = "March 4, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Tarnished Undermine Real now drop from Ruins of Ahn’Qiraj and Temple of Ahn’Qiraj bosses and hard mode caches.", level = 0 },
            { type = "list_item", text = "Nightmare Grove", level = 0 },
            { type = "list_item", text = "The Nightmare Dragons now drop three Tarnished Undermine Reals each.", level = 1 },
            { type = "list_item", text = "The Nightmare Dragons now each drop a piece of Non-C’thun Temple of Ahn’Qiraj Tier.", level = 1 },
            { type = "list_item", text = "Players can access to the Temple of Ahn’Qiraj vendors at the entrance of the raid. These NPCs are Kandrostrasz, Vethsera, and Andorgos.", level = 2 },
            { type = "list_item", text = "The Nightmare Dragons now each drop a piece of Blackwing Tier that is not available on the Undermine Real vendor. (Shoulders/Legs/Head/Chest).", level = 1 },
            { type = "list_item", text = "The Nightmare Dragons now each drop a Blackwing Lair class trinket.", level = 1 },
            { type = "list_item", text = "All of the pieces in the Nightmare Dragon’s old loot has had 8 primary armor slots updated to have the Timeworn tag, allowing them to interact with the Signet Ring of the Bronze Dragonflight line.", level = 1 },
            { type = "list_item", text = "To allow players more chances to get missing patterns, the Nightmare Dragons can now drop all of the enchanting and engineering patterns from Molten Core and all professions recipes from Ahn’Qiraj.", level = 1 },
            { type = "list_item", text = "Health of all bosses and enemy creatures reduced by 15%.", level = 1 },
            { type = "list_item", text = "Damage and healing of all bosses and enemy creatures reduced by 30%.", level = 1 },
            { type = "list_item", text = "All Dragons no longer thrash.", level = 1 },
            { type = "list_item", text = "Emeriss - NPC priests during the PvP raid phase no longer cast Mind Control.", level = 1 },
            { type = "list_item", text = "Lethon - Damage reduction aura from the large Spirit Shade reduced to 50% (was 99%), and movement speed of Spirit Shades lowered by 25%.", level = 1 },
            { type = "list_item", text = "Ysondre - Divergent Lightning is now cast less frequently and deals less damage.", level = 1 },
            { type = "p", text = "February 28, 2025Season of Discovery" },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Blade Flurry no longer receives double % increases.", level = 1 },
            { type = "dev_note", text = "This affects Seal of the Dawn and Rogue set bonuses. Now, % increases from hostile Mind Controls like Chains of Kel’thuzad or Prophet Skeram’s Mind Control no longer cause massive amounts of damage from Blade Flurry.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Sweeping Strikes no longer receives double % increases while inside of Naxxramas.", level = 1 },
            { type = "dev_note", text = "Due to Warriors having multiple % increases in their kit through Enrage, we did not want to impact their PvP performance with this bugfix, so this only applies to Warriors while inside Naxxramas. This means Seal of the Dawn and Warrior set bonuses are no longer doubled, and % increases from hostile Mind Controls inside of Naxxramas like Chains of Kel’thuzad no longer cause massive amounts of damage from Sweeping Strikes.", level = 2 },
            { type = "p", text = "February 27, 2025Season of Discovery" },
            { type = "list_item", text = "There should no longer be extra enemies near the objectives of The Dark Hoard quest in Blackrock Spire.", level = 0 },
            { type = "list_item", text = "Hardened Frostguard now has an internal cooldown on the Frost Nova chance on hit, to prevent it from extensively reactivating on the same ability cast.", level = 0 },
            { type = "list_item", text = "Naxxramas", level = 0 },
            { type = "list_item", text = "Ignite will no longer incorrectly tick on targets while the player is under the effect of a Mind Control.", level = 1 },
            { type = "list_item", text = "The health increases from Lifegiving Gem, Rallying Cry, Last Stand, Aegis of Preservation, Vengeance, and Survival Instincts no longer behave incorrectly while under the effects of the Seal of the Dawn.", level = 1 },
            { type = "list_item", text = "While inside Naxxramas, the 6-piece bonuses for tank warrior, tank warlock, and tank druid will now dynamically update your Last Stand, Vengeance, and Survival Instincts if the new value would be lower and you do not have a debuff that lowers your health active.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The tank T1 6-piece set bonus now provides a 20% damage reduction (was 50%).", level = 1 },
            { type = "list_item", text = "The animation for Crimson Tempest has been changed to be less chaotic.", level = 1 },
            { type = "h3", text = "February 21, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Soul shoulder enchants are now stackable up to 20. Once purchased, these cannot be refunded.", level = 0 },
            { type = "list_item", text = "Wartorn Undermine Supply Crates now contain about twice as many Wartorn Scraps as before.", level = 0 },
            { type = "list_item", text = "Undead Slaying set bonuses now activate at 2 pieces (was 3).", level = 0 },
            { type = "list_item", text = "Karazhan Crypts", level = 0 },
            { type = "list_item", text = "Added a chance for Kharon and the Dark Rider to drop the neck piece from the apprentice you did NOT unlock.", level = 1 },
            { type = "dev_note", text = "For example, if you release Kaigy Maryla, Kharon now has a chance to drop Sairuh’s Collar, and the Dark Rider now has a chance to drop Barian’s Choker. We are aware you can summon the Dark Rider before releasing an apprentice. If this happens, the Dark Rider does not have an additional drop chance.", level = 1 },
            { type = "list_item", text = "Naxxramas", level = 0 },
            { type = "list_item", text = "The exit portal that spawns in Sapphiron’s room after the boss has been defeated will now persist after players leave and soft reset the instance.", level = 1 },
            { type = "list_item", text = "The gates blocking entrance into the various wings of Naxxramas will now stay open forever if Kel’Thuzad has been defeated.", level = 1 },
            { type = "list_item", text = "Fixed an issue where the number of bosses killed on the hardest difficulty weren’t tracking properly if you soft reset your raid after killing Four Horsemen.", level = 1 },
            { type = "list_item", text = "Raid groups in a bugged state will be able to fight Sapphiron and Kel’Thuzad on their hard-mode difficulties after soft resetting their instances.", level = 2 },
            { type = "list_item", text = "The Spore Buff on Loatheb will no longer count towards the Dance of the Wicked dodge chance.", level = 1 },
            { type = "list_item", text = "The Spore Buff on Loatheb will no longer count towards the Elemental Shaman Ruins of Ahn’Qiraj 3-piece bonus, the Retribution Paladin T3 6-piece bonus, or the Shadow Priest T3 6-piece bonus for the purposes of increasing damage.", level = 1 },
            { type = "list_item", text = "Sapphiron’s Glacial Crash now correctly splits its damage amongst players, no longer benefits from the player’s % damage modifiers, and Glacial Crash damage has been increased to the correct amount without accounting for player % damage modifiers.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "The Restoration T3 6-piece set bonus will now correctly work against Sapphiron’s Frost Aura ticks", level = 1 },
            { type = "list_item", text = "The Feral damage T3 2-piece bonus now mentions in its tooltip that it will not be effective against players.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Ranged Hunter T3 2-piece now correctly increases the damage dealt by Chimera Shot - Serpent.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Mass Regeneration will correctly update the duration of Temporal Beacons on players who have a Temporal Beacon from another Mage with a longer than 15 second duration.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "The Retribution T3 6-piece bonus now mentions that it does not work while Righteous Fury or Hand of Reckoning are active.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Serendipity now correctly applies to your next Lesser Heal, Heal, Greater Heal, or Prayer of Healing even if they were spell queued before a Serendipity was present.", level = 1 },
            { type = "list_item", text = "Penance is no longer affected by Spell Haste that benefits non-channeled spells.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The tooltip for the Restoration T3 6-piece set bonus now correctly mentions Earth Shield instead of Spirit of the Alpha.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Haunt will no longer incorrectly increase the impact damage of Shadowflame.", level = 1 },
            { type = "list_item", text = "Improved Immolate will no longer incorrectly increase the damage from the Warlock T3 Shadowflame hit.", level = 1 },
            { type = "list_item", text = "The Scythe of Chaos will now correctly do its Felhunter Silence and Interrupt.", level = 1 },
            { type = "list_item", text = "Damage Warlock T3 6-piece bonus now correctly ties the Mark of Chaos effect to the Curse of Agony cast and not to the Curse of Recklessness that is applied through the bonus. This prevents Mark of Chaos from falling off if Curse of Recklessness is replaced by another Warlock.", level = 1 },
            { type = "list_item", text = "Haunt will no longer incorrectly increase the impact damage of Shadowflame.", level = 1 },
            { type = "list_item", text = "Improved Immolate will no longer incorrectly increase the damage from the T3 Shadowflame hit.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Fresh Meat will now correctly have a 100% chance to proc on an encounter after a wipe.", level = 1 },
            { type = "list_item", text = "Fresh Meat will now correctly have a 100% chance to proc against a target in PvP if the target player leaves combat with the Warrior.", level = 1 },
            { type = "list_item", text = "Revenge attack power multiplier increased by 25% (was 15%).", level = 1 },
            { type = "hr" },
            { type = "h3", text = "February 14, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "In Season of Discovery, all buffs from the Lunar Festival and Love Is In The Air events require the holiday to be active. After the events end, event items cannot be consumed, and they will be removed upon log-in.", level = 0 },
            { type = "list_item", text = "Might of Menethil now has a chance on hit to knocks down all nearby enemies for 4 seconds.", level = 0 },
            { type = "list_item", text = "Naxxramas", level = 0 },
            { type = "list_item", text = "Kel’thuzad will no longer rot faster than intended on maximum difficulty.", level = 1 },
            { type = "list_item", text = "Kel’thuzad will no longer allow players to use a Flask of Petrification to avoid engaging with his mechanics on maximum difficulty.", level = 1 },
            { type = "list_item", text = "Temple of Ahn’Qiraj", level = 0 },
            { type = "list_item", text = "Huhuran will no longer retain stacks of Frenzy after a wipe.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "The Tier 3 Feral Druid 2-piece bonus will no longer increase the frequency of Rake’s periodic against players.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Tranquilizing Shot will no longer remove stacks of the Tier 3 Melee Hunter 6-piece bonus.", level = 1 },
            { type = "list_item", text = "Feign Death will now set the remaining duration of the Tier 3 Undead Slaying bonus to 5 seconds, providing an opportunity to get back into combat to keep the bonus stacks.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Mages will no longer have a chance to instantly kill players when they are Mind Controlled.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Righteous Fury will no longer incorrectly fall off if the target that dealt damage to the Paladin is no longer available/alive.", level = 1 },
            { type = "list_item", text = "The Tier 1 Holy Paladin 6-piece bonus will now correctly gain healing based on your Sanctified bonus.", level = 1 },
            { type = "list_item", text = "The Holy Paladin Temple of Ahn’Qiraj 4-piece bonus will no longer incorrectly benefit twice from your Sanctified healing bonus.", level = 1 },
            { type = "list_item", text = "The Tier 3 Retribution Paladin 6-piece set bonus will no longer work if you have Hand of Reckoning engraved or Righteous Fury active.", level = 1 },
            { type = "dev_note", text = "We feel that this would turn a Paladin tank into a one-button playstyle while also providing too much damage for a tank. With this change, Protection Paladins can exchange their Retribution Tier for Tank Tier until the February 20. This is a one-way trade.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "The Tier 1 Shadow Priest 6-piece bonus should now more responsively to add the Melting Faces buff to players after a Mind Blast crit, allowing an empowered Mind Flay to be immediately channeled.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Soul of the Phantom will now correctly apply to Rogues upon logging in.", level = 1 },
            { type = "list_item", text = "Fixed an issue preventing Rogues from getting a Sending Sigil if they knew the Engrave Blunderbuss rune.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The Temple of Ahn’Qiraj 4-piece Enhancement set now correctly works against Bleed-Immune targets.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Shadowflame and Immolate no longer gain increased critical damage from Pandemic. This increase is from the Ruin talent.", level = 1 },
            { type = "h3", text = "February 13, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Scourge Invasions", level = 0 },
            { type = "list_item", text = "The rate at which undead spawn at the Scourge Invasion camps has been greatly increased. This increases both the number of creatures present as well as the rate at which more spawn, making invasion camps much more dangerous. As a reminder, you cannot loot another Heart of Doom if you have looted one within the last 5 minutes.", level = 1 },
            { type = "list_item", text = "Remnants of Valor now drop once per day from bosses in Scholomance and Stratholme Dead Side bosses. These are on the same timer as Tarnished Undermine Real dropping once daily from bosses.", level = 1 },
            { type = "list_item", text = "Every zone that has a Scourge Invasion now also has a soul projection of Brother Luctus for picking up and turning in the repeatable quest.", level = 1 },
            { type = "list_item", text = "You can now exchange Remnants of Valor for Argent Dawn Valor Tokens from Brother Luctus.", level = 1 },
            { type = "list_item", text = "Next week, the Seal of the Dawn will only go up 1 maximum rank, to rank 5.", level = 1 },
            { type = "dev_note", text = "We previously expected to increase the Seal of Dawn power system to rank 6 next week, but have determined that it would be better to slow it down and possibly cap it earlier than rank 10. This also means that players will not have to obtain as many Remnants of Valor each week. We will continue to track and evaluate this system.", level = 2 },
            { type = "list_item", text = "Karazhan Crypts", level = 0 },
            { type = "list_item", text = "Remnants of Valor now drop from Karazhan Crypts bosses.", level = 1 },
            { type = "list_item", text = "Ultravision cannot be removed by immunities.", level = 1 },
            { type = "list_item", text = "Flametongue Totem now grants protection from Oppressive Darkness.", level = 1 },
            { type = "list_item", text = "Naxxramas", level = 0 },
            { type = "list_item", text = "A portal has been added inside of the entrance to Naxxramas that will allow players to exit the instance.", level = 1 },
            { type = "list_item", text = "A portal has been added in the Frostwyrm Lair that becomes active when Sapphiron is defeated, allowing players to return to the entrance of Naxxramas.", level = 1 },
            { type = "h3", text = "February 11, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Reduced the cost of World Buff consumables and reputation items purchased with Commendation Signets by 50%. World Buff consumable items now stack up to 20.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused Scourge invasions to respawn slower based on number of layers on a realm. Scourge invasions now respawn regardless of the number of layers.", level = 0 },
            { type = "list_item", text = "The spawn rate of Blood of Heroes in both Eastern Plaguelands and Western Plaguelands has been adjusted to accommodate the additional vendor cost of Tier 3 set rings.", level = 0 },
            { type = "list_item", text = "Enriched Manna Biscuits from Argent Dawn reputation now restore a percentage of your health per second while inside Naxxramas, to allow players who have large health pools with the Seal of the Dawn active to get back on their feet faster.", level = 0 },
            { type = "list_item", text = "The Violet Satchel quest now correctly requires the Violet Satchel and consumes it on turn in. Once the Violet Satchel quest has been completed, the Violet Satchel and Scrap of Parchment no longer drops. If you have completed this quest previously and have any of these in your inventory now, you can safely delete these items.", level = 0 },
            { type = "list_item", text = "Karazhan Crypts", level = 0 },
            { type = "list_item", text = "Fixed an issue that was causing the Dark Rider to despawn during the Torment’s Illusion mechanic.", level = 1 },
            { type = "list_item", text = "The Frostbolt Volley from Sairuh Maryla in the Karazhan Crypts now has the correct tooltip on its debuff, and now slows players whenever it hits them, regardless of how far away they were.", level = 1 },
            { type = "list_item", text = "Kharon: The Red Death can no longer hit mind-controlled targets.", level = 1 },
            { type = "list_item", text = "Naxxramas", level = 0 },
            { type = "list_item", text = "Instructor Razuvious’ Disrupting Shout will now correctly be reduced by pet Avoidance.", level = 1 },
            { type = "list_item", text = "Heigan’s Mana Burn will now correctly be reduced by pet Avoidance.", level = 1 },
            { type = "list_item", text = "Kel’Thuzad’s Void Fissures will no longer hit pets.", level = 1 },
            { type = "dev_note", text = "We’ve reduced the requirement to micromanage your pet’s movement in cases where it doesn’t result in practical gameplay. We’ve retained mechanics such as Detonate Mana striking pets, or Sapphiron’s Drain Life and Heigan’s Disease hitting pets, as these provide gameplay moments beyond merely avoiding damage through movement.", level = 2 },
            { type = "list_item", text = "Gothik the Harvester", level = 1 },
            { type = "list_item", text = "Reduced the health of Gothik and his summons.", level = 2 },
            { type = "list_item", text = "The Four Horsemen", level = 1 },
            { type = "list_item", text = "Spirits of the Horsemen should no longer persist through resets.", level = 2 },
            { type = "list_item", text = "Sapphiron", level = 1 },
            { type = "list_item", text = "Avoidance now correctly works on Sapphiron’s Frost Aura.", level = 2 },
            { type = "list_item", text = "Sapphiron’s Frost Breath will no longer hit pets that have an Avoidance aura on them.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "The Restoration Druid Tier 3 2-piece set bonus will now correctly proc once every few seconds (was a proc on every instance of damage).", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Changed the Melee Hunter Set so that the 6-piece effect falls off if you perform a ranged attack. Players can speak to Huntsman Leopold to exchange their Melee Tier 3 Hunter pieces, one way, for the Ranged Tier 3 Hunter pieces. This is a one-way trade, and the exchange will be removed on February 13.", level = 1 },
            { type = "list_item", text = "A previously deleted Infernal Lasso can now be recovered from the Lost and Found vendor in Booty Bay.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "The Healing Mage Tier 3 2-piece bonus will now correctly scale with Sanctified gear while inside of Naxxramas.", level = 1 },
            { type = "list_item", text = "Fixed a problem where Mass Regeneration was replacing longer duration Temporal Beacons with shorter duration ones. It will no longer overwrite longer duration ones with shorter duration ones.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Seal of Martyrdom will now restore the correct amount of Mana while outside of Naxxramas if you have a Seal of the Dawn buff active.", level = 1 },
            { type = "list_item", text = "The Retribution Tier 3 4-piece set bonus will no longer reset your swing timer when Holy Wrath is cast.", level = 1 },
            { type = "list_item", text = "The Holy Paladin Tier 3 2-piece bonus will now correctly restore mana to the Paladin instead of their target when Lay on Hands is cast.", level = 1 },
            { type = "list_item", text = "The Protection Paladin Tier 3 4-piece bonus applies correctly to the Malleable Protection version of Divine Protection.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The Rogue Tier 3 2-piece set bonus now increases the damage of Backstab by 10% (was 5%).", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The Restoration Shaman Tier 3 helm now correctly has Spell Haste.", level = 1 },
            { type = "list_item", text = "The Restoration Shaman Tier 3 2-piece bonus will no longer erroneously remove the internal cooldown of Earth Shield.", level = 1 },
            { type = "list_item", text = "Reduced the Tank Shaman Tier 3 4-piece bonus additional damage reduction to 10% (was 15%).", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "The Tank Warlock Tier 2.5 4-piece bonus will now correctly remove the effects of Demonic Sacrifice if you summon an Incubus or Succubus when the other one was the target of Demonic Sacrifice.", level = 1 },
            { type = "list_item", text = "Reduced the Warlock Tank Tier 3 4-piece bonus cooldown reduction on Demonic Grace reduced to 3 seconds (was 10 seconds).", level = 1 },
            { type = "list_item", text = "Reduced the Warlock Tank Tier 3 4-piece bonus cooldown reduction on Infernal Armor to 10 seconds (was 30 seconds).", level = 1 },
            { type = "h3", text = "February 4, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Fixed an issue where players are no longer able to accept and complete the Tier 0.5 quests.", level = 0 },
            { type = "list_item", text = "Shortened the Injured adventurer’s respawn time for the quest “To the Rescue”, so that he becomes available again more rapidly after being rescued and running off. Quest credit should be awarded to players who are dead when the cage is opened and the adventurer is freed.", level = 0 },
            { type = "list_item", text = "There is now a Haunted Anvil in the town outside of Karazhan that players may interact with to repair their gear, whether they are living or dead.", level = 0 },
            { type = "list_item", text = "Repeatable quests for Remnants of Valor are now available. Players can now pick this quest up from Brother Luctus at Light’s Hope Chapel if they have completed the prerequisite quest.", level = 0 },
            { type = "list_item", text = "Heart of Doom can now be looted for the repeatable Remnants of Valor quest from the Heart of Doom object that spawns after a Shadow of Doom has perished. These will now only last for a short time after the death of a Shadow of Doom.", level = 0 },
            { type = "list_item", text = "The Heart of Doom that spawns after a Shadw of Doom is killed will now last for 5 minutes, giving players more of an opportunity to click it. Once you have successfully looted a Heart of Doom, you may not loot another for 5 minutes.", level = 0 },
            { type = "list_item", text = "Argent Dawn Quartermasters and Outfitters now offer all Undead Slaying gloves quests available to your armor type. Previously full sets were locked to the highest armor type a class can wear.", level = 0 },
            { type = "list_item", text = "Weighted Consecrated Sharpening Stone can now correctly be applied to Staves.", level = 0 },
            { type = "list_item", text = "Karazhan Crypts", level = 0 },
            { type = "list_item", text = "Demon Charge and Feral Charge now destroy the Immense Rock.", level = 1 },
            { type = "list_item", text = "Players will now be able to loot a bag containing a Necrotic Rune from every boss and mini-boss.", level = 1 },
            { type = "list_item", text = "Shamans can now cleanse the Diseased Corpse.", level = 1 },
            { type = "list_item", text = "Mysterious Relics are now Bind on Pickup and Uncommon.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "The Darkrider’s Spine will now correctly use and benefit from Arrows.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Binding Heal now correctly benefits from and is consumed by Inner Focus.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Fixed an issue where Curse of Agony was not gaining any benefit from Improved Curse of Agony or Amplify Curse.", level = 1 },
            { type = "h3", text = "January 30, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "You can now correctly hand in Supply Shipments from Karazhan to Supply Officers in cities.", level = 0 },
            { type = "list_item", text = "The “Shadow of Doom” Scourge Invasion quest can now be completed while in a raid group. Everyone in the group will get credit for the kill of the Shadow of Doom.", level = 0 },
            { type = "list_item", text = "Shadows of Doom now spawn an interactable Heart of Doom that players can loot to start their shoulder enchant quest. When getting Hearts of Doom in the future for Remnants of Valor after Naxxramas releases, players will need to get the tag on Shadows of Doom.", level = 0 },
            { type = "list_item", text = "The tooltip on the Doomsayer’s Demise Wand now correctly states that it deals 100 damage per stack of Creeping Darkness (was 45 damage per stack of Creeping Darkness). The tooltip on the Wand does not change when the set is completed, but the debuff tooltip on enemies will increase.", level = 0 },
            { type = "list_item", text = "Tome of Enchanted Flare can now only be seen and looted by Hunters.", level = 0 },
            { type = "list_item", text = "The “Elemental Equation” and the “Core of Elements” quests can now be completed in Light’s Hope Chapel.", level = 0 },
            { type = "p", text = "January 21, 2025Season of Discovery" },
            { type = "list_item", text = "All Season of Discovery World buffs will be removed from Classic Era and Anniversary Realm characters upon login or entering an instance.", level = 0 },
            { type = "list_item", text = "Divine Steed is now available on the Rune Broker at level 45.", level = 0 },
            { type = "list_item", text = "Equipping the Revered Version of the DPS Signet Ring of the Bronze Dragonflight will no longer cause it to launch a Timeworn Shot.", level = 0 },
            { type = "list_item", text = "You can now refund the tier tokens from the Undermine Reals.", level = 0 },
            { type = "h3", text = "January 14, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Real vendor now sells All Tier 1 and half of the Tier 2 Tokens", level = 0 },
            { type = "list_item", text = "Tier 1 Wrists/Waist/Hands - 15 Tarnished Undermine Reals", level = 1 },
            { type = "list_item", text = "Tier 1 Feet/Shoulders - 20 Tarnished Undermine Reals", level = 1 },
            { type = "list_item", text = "Tier 1 Chest/Legs/Head - 25 Tarnished undermine Reals", level = 1 },
            { type = "list_item", text = "Tier 2 Wrists/Waist/Hands/Feet - 35 Tarnished Undermine Reals", level = 1 },
            { type = "dev_note", text = "We currently have no plans to further expand the raid equipment present on the Undermine Real vendor, and we’ve focused this change exclusively on giving newer characters access to set bonuses that may be critically impactful to their character progression.", level = 1 },
            { type = "list_item", text = "C’thun will now drop 1 additional item in all difficulties. This item will be either an additional Chest Tier piece, or one of the highly desired weapons from the instance for damage dealers and healers.", level = 0 },
            { type = "list_item", text = "Thorns effects from items (aside from Nagelring) will now log into the combat log.", level = 0 },
            { type = "dev_note", text = "The behavior of these items is unchanged. This update adds information to the combat log that previously was only displayed on-screen.", level = 1 },
            { type = "list_item", text = "Many Ahn’Qiraj crafting patterns have had their required materials lowered:", level = 0 },
            { type = "list_item", text = "This includes Glowing Chtin Armor Kit, Sharpened Silithid Chitin Armor Kit, Tuned Force Reactive Disk, Obsidian Scope, Enchanted Stopwatch, Tear of the Dreamer, Lodestone of Retaliation, Totem of Flowing Magma, Totem of Pyroclastic Thunder, Totem of Thunderous Strikes, Enchanted Totem, Qiraji Silk Cape, Qiraj Silk Cloak, Qiraji Silk Drape, Qiraji Silk Scarf, Razorspike Battleplate, Razorspike Headcage, and Razorspike Shoulderplate.", level = 1 },
            { type = "h3", text = "January 13, 2025" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The Protection Paladin T2.5 two-piece bonus is now correctly removed when the set bonus is broken.", level = 0 },
            { type = "list_item", text = "You can no longer use Fresh Holly, or Preserved Holly while Divine Steed is active.", level = 0 },
            { type = "list_item", text = "Shadowfiend can no longer be used in Neutral cities to cause the guards to attack the target that was engaged upon.", level = 0 },
            { type = "list_item", text = "Various Cat Form Druid abilities such as Berserk, Savage Roar, and Wild Strikes will now work properly during the Nefarion Druid Class call.", level = 0 },
            { type = "h3", text = "December 17, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Added a Rune Broker vendor to every starting area. This vendor will provide access to all class runes at level 1.", level = 0 },
            { type = "dev_note", text = "Some discoveries in the game world may not function properly if you learn the related rune ability from items purchased on this vendor.", level = 1 },
            { type = "list_item", text = "Fixed an issue that prevented Ring Specialization runes from being available on Rune Brokers.", level = 0 },
            { type = "list_item", text = "Increased the drop rates of Hive Thistle, Small Obsidian Shards, and Large Obsidian Shards in Silithus and Ahn’Qiraj. Every herb node in Silithus is now guaranteed to have 2-4 Hive Thistle. All Large Obsidian nodes now always have 1-2 Large Obsidian Shards and 3-5 Small Obsidian Shards. All Small Obsidian nodes now always have 2-4 Small Obsidian Shards and a (larger than before) chance of a Large Obsidian Shard.", level = 0 },
            { type = "dev_note", text = "These changes only apply to new spawns of the nodes, so until every node has been re-spawned, there may still be some that behave as they did before the change.", level = 1 },
            { type = "list_item", text = "Temple of Ahn’Qiraj", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused the Twin Emperors to continue spawning Eye Tentacles after combat had expired.", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused the Twin Emperors to fail to respawn.", level = 1 },
            { type = "h3", text = "December 13, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Tarnished Undermine Real drops in Molten Core and Blackwing Lair increased to 3 per boss (was 1).", level = 0 },
            { type = "list_item", text = "Damaged Undermine Supply Crates cost increased to 10 (was 5), and will now always contain some of the new Ahn’Qiraj crafting reagents, Scarabs, Idols from the Ruins or an Idol from the Temple of Ahn’Qiraj.", level = 0 },
            { type = "list_item", text = "Using any of the world buff consumable items will no longer cause party and raid members to stop eating or drinking.", level = 0 },
            { type = "list_item", text = "Ruins of Ahn’Qiraj", level = 0 },
            { type = "list_item", text = "Activating an Obelisk inside the raid will no longer interrupt player’s eating or drinking.", level = 1 },
            { type = "list_item", text = "The Obelisk to continue opting into the Descent into Madness has been shifted to be underneath the large water pipe that leads down to the encounter space.", level = 1 },
            { type = "list_item", text = "Moam and Ayamiss have had their health reduced.", level = 1 },
            { type = "list_item", text = "Noxious Burst should now correctly grab targets to deal damage on detonation and not application.", level = 1 },
            { type = "list_item", text = "Non-boss-enemy drops from Ruins of Ahn’Qiraj have been added and distributed across the first three bosses (previously were only obtainable from the chests).", level = 1 },
            { type = "list_item", text = "Temple of Ahn’Qiraj", level = 0 },
            { type = "list_item", text = "Activating an Obelisk inside the raid will no longer interrupt player’s eating or drinking.", level = 1 },
            { type = "list_item", text = "Ouro should no longer summon the Eye of C’thun if the Descent into Madness is not active.", level = 1 },
            { type = "list_item", text = "Noxious Burst should now correctly grab targets to deal damage to on detonation and not application.", level = 1 },
            { type = "list_item", text = "C’thun", level = 1 },
            { type = "list_item", text = "Tentacles should no longer spawn while C’thun is vulnerable in Phase 2.", level = 2 },
            { type = "list_item", text = "Digestive Acid once again stacks.", level = 2 },
            { type = "list_item", text = "The frequency at which some tentacles spawn has been reduced.", level = 2 },
            { type = "h3", text = "December 11, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Removed gear from player-characters who obtained it from an unintentionally available testing NPC.", level = 0 },
            { type = "list_item", text = "The new relics that are crafted from Ahn’Qiraj are no longer Unique.", level = 0 },
            { type = "list_item", text = "Players dying outside the entrance to the areas of the Gates of Ahn’Qiraj, The Scarab Dais, or The Scarab Wall will now use the same graveyard as those who die inside Ruins or Temple of Ahn’Qiraj raids.", level = 0 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Divine Light will now correctly activate Scarab Brooch.", level = 1 },
            { type = "h3", text = "December 10, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Elixir of the Ironside now grants 450 armor.", level = 0 },
            { type = "dev_note", text = "This makes it so that consuming an Elixir of Superior Defense alongside an Elixir of the Ironside has no added benefit.", level = 1 },
            { type = "list_item", text = "Ahn’Qiraj", level = 0 },
            { type = "list_item", text = "Some Obelisks for the Descent into Madness have been moved to more accessible, easily visible locations.", level = 1 },
            { type = "list_item", text = "Huhuran’s berserk should now correctly clear after she resets.", level = 1 },
            { type = "list_item", text = "Obelisks that were not triggered should now be correctly unavailable after a boss is defeated. The Descent into Madness should now correctly shut off after a boss is defeated if their respective Obelisk is not interacted with.", level = 1 },
            { type = "list_item", text = "The Gilded Scarab should now properly award loot when defeated.", level = 1 },
            { type = "list_item", text = "The hard mode caches in the Ruins of Ahn’Qiraj raid will now contain keys for the instance’s scarab coffers.", level = 1 },
            { type = "list_item", text = "Master Loot and item trading work once again for Viscidus and Princess Huhuran in Ahn’Qiraj from the Caches of Wagering.", level = 1 },
            { type = "list_item", text = "Ouro should now correctly respawn if he despawns during his burrow phase.", level = 1 },
            { type = "list_item", text = "Reduced the health of Fankriss and his spawn, and Spawn of Fankriss damage reduced.", level = 1 },
            { type = "list_item", text = "Increased the health of many of the creatures inside the Ruins of Ahn’Qiraj.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Fixed an issue where Druids were able to use Shred from in front of a target if they were very close to the target. It now properly always requires behind (unless they have the Season of Discovery set bonus that removes this restriction).", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The 3-piece Ruins of Ahn’Qiraj set bonus for Rogues will now correctly reduce the cost of Crimson Tempest.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Revenge Rank 6 now correctly benefits from attack power.", level = 1 },
            { type = "h3", text = "December 9, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Ahn’Qiraj", level = 0 },
            { type = "list_item", text = "New flasks from Ahn’Qiraj now stack to 20 (was 1). Older flasks stack to 5, unchanged.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Moonkin Form now grants 3 spell damage per level (was 2).", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "The Shadow T2.5 2-piece set bonus will now correctly launch a free Mind Flay when starting the first cast of Mind Flay.", level = 1 },
            { type = "h3", text = "December 4, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Anachronos will now allow you to get another Scepter of the Shifting Sands if yours is misplaced.", level = 0 },
            { type = "list_item", text = "The Season of Discovery versions of the original Darkmoon Cards are now obtainable from their quests.", level = 0 },
            { type = "list_item", text = "Songflower Lullaby, Dark Fortune of Damage, and Blessing of Neptulon will no longer cancel when entering instances.", level = 0 },
            { type = "list_item", text = "Players can now go into Blackwing Lair and change any Tier 2 items with Tier 1 set bonuses back into the Tier 2 item with Tier 2 set bonuses.", level = 0 },
            { type = "list_item", text = "Draught of the Sands for Hunters and Rogues will no longer erroneously stack under certain conditions.", level = 0 },
            { type = "list_item", text = "Unbalancing Strike from the Twin Emperors encounter in the Temple of Ahn’Qiraj will no longer affect the bonus attack power or spell damage gained from Defender’s Resolve. You will always gain these stats based on your pre-Unbalancing Strike defense skill.", level = 0 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Moonkin Form now grants 3 spell damage per level (was 2).", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Tranquilizing Shot will no longer consume a stack of Lock and Load.", level = 1 },
            { type = "list_item", text = "Resourcefulness no longer erroneously reduces the cooldown of Deterrence.", level = 1 },
            { type = "list_item", text = "Tranquilizing Shot will once again correctly work against the SIlithid Darter during the Hunter Quest chain.", level = 1 },
            { type = "list_item", text = "Swapping off of Rapid Killing to Lock and Load now prevents the use of Lock and Load for 60 seconds.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fire Mage Tier 2.5 4-piece bonus decreased to 10% (was 20%).", level = 1 },
            { type = "list_item", text = "Fire Mage Ruins of Ahn’Qiraji 3-piece set bonus decreased to 9% (was 20%).", level = 1 },
            { type = "list_item", text = "Living Bomb now has an additional line of text that reads: “Living Bomb benefits from all talents and effects that trigger from or modify Scorch” allowing ticks of Living Bomb and the Explosion to apply Fire Vulnerability if talented.", level = 1 },
            { type = "list_item", text = "Fingers of Frost has a 25% chance to activate (was 15%).", level = 1 },
            { type = "list_item", text = "Ice Lance damage from spell power increased by 300%.", level = 1 },
            { type = "list_item", text = "Ice Lance deals 400% damage to frozen targets (was 300%).", level = 1 },
            { type = "list_item", text = "The Ice Lance rune now has a passive that states “When your other frost spells deal damage to a non-player-controlled target, they increase the target’s damage taken from your next Ice Lance by 20%. This effect stacks up to 5 times and requires the Winter’s Chill talent.”", level = 1 },
            { type = "list_item", text = "Wrath of Cenarius will now correctly proc from Balefire Bolt, Spellfrost Bolt, and Frozen Orb.", level = 1 },
            { type = "list_item", text = "Mages can no longer consume another mage’s Glaciate stacks.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "The T2.5 Shadow Priest 4-piece set bonus has been decreased to 10% increased Mind Spike damage (was 20%).", level = 1 },
            { type = "list_item", text = "The T1 6-piece Shadow set bonus will now correctly consume the Melting Faces buff after casting Mind Flay.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The Draught of the Sands now has a version for Rogues available from vendors.", level = 1 },
            { type = "list_item", text = "Unbalancing Strike from the Twin Emperor’s encounter in the Temple of Ahn’Qiraj will no longer cause the Rogue to lose any of their Physical Damage Reduction gained through their defense skill and Blade Dance.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Different ranks of Flame Shock will no longer stack.", level = 1 },
            { type = "list_item", text = "Flame Shock’s original sound effect has been restored.", level = 1 },
            { type = "list_item", text = "Lava Lash’s bonus damage from Flametongue Weapon reduced from to 100% (was 125%).", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Scythe of Chaos will no longer kill your pet, but instead dismiss it, allowing it to retain its buffs when resummoned.", level = 1 },
            { type = "list_item", text = "Warlock pets will now correctly inherit their master’s Fire or Shadow spell hit chance based on whichever is higher.", level = 1 },
            { type = "list_item", text = "Warlock pets will now correctly gain full value of spell hit chance for their spells.", level = 1 },
            { type = "list_item", text = "Warlock pets will now correctly gain 80% of their master’s spell hit as physical hit.", level = 1 },
            { type = "list_item", text = "Warlock pets will gain -0.5 reduction to their chance to be dodged or parried if any ring rune is engraved on their master.", level = 1 },
            { type = "list_item", text = "The Tank Warlock T2 two-piece set bonus will no longer use the target’s health to life tap if you are in a neutral city.", level = 1 },
            { type = "list_item", text = "If Mark of Chaos is applied by Curse of Agony, Mark of Chaos will now linger for 3 seconds after the Curse of Agony aura fades.", level = 1 },
            { type = "dev_note", text = "This is to allow Warlocks who are using Curse of Agony to have a window where they can let their Curse of Agony fully fade, and not lose the raid’s Mark of Chaos debuff before they reapply it. This will eliminate the need to clip the end of a Curse of Agony in order to benefit the raid.", level = 2 },
            { type = "h3", text = "December 2, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Blackwing Lair", level = 0 },
            { type = "list_item", text = "Applying at least 1 affix in Blackwing Lair will now add an additional item to the loot cache. This item will be one of your faction’s 8 class trinkets.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Feral damage 2-piece Tier 2.5 set bonus now increases Shred damage by 15% (was 20%).", level = 1 },
            { type = "list_item", text = "Mangle (Bear) Threat modifier increased to 1.5x threat per damage (was 1.0x threat per damage).", level = 1 },
            { type = "list_item", text = "Lacerate’s impact Threat modifier decreased to 3.33x threat per damage (was 3.5x threat per damage).", level = 1 },
            { type = "list_item", text = "Lacerate’s damage over time Threat modifier decreased to 3.33x threat per damage (was 3.5x threat per damage).", level = 1 },
            { type = "dev_note", text = "The threat changes are intended to assist in snap threat for Tank Druids, giving more value to using Berserk on the opening of a fight while retaining the value in stacking a lacerate.", level = 2 },
            { type = "list_item", text = "The following Balance Druid updates were implemented on November 19, 2024:", level = 1 },
            { type = "list_item", text = "Improved Frenzied Regeneration can no longer be used in Moonkin Form", level = 2 },
            { type = "list_item", text = "Survival Instincts can no longer be used in Moonkin Form", level = 2 },
            { type = "list_item", text = "Dreamstate’s increase to Nature and Arcane damage taken, can no longer be applied to players.", level = 2 },
            { type = "dev_note", text = "These changes are targeted at Moonkin’s frustrations in PvP encounters. They will still have an option in these slots rune-wise for PvP, albeit way less durable or bursty, in the form of Elune’s Fire. Dreamstate will still provide the mana regeneration in PvP. This also made room for the talent adjustments made recently to buff up Improved Moonfire and Moonfury.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Ranged Hunter Tier 2.5 2-set bonus is now a 20% increase to Kill Shot damage against non-player-controlled targets.", level = 1 },
            { type = "list_item", text = "Swapping to the Kill Shot rune will now correctly place it on a 12 second cooldown (was 15 seconds), adjusted for its new base cooldown.", level = 1 },
            { type = "list_item", text = "Swapping off of the Kill Shot rune will now place Flanking Strike on a 12 second cooldown, and prevent the stacking of Sniper Training for 12 seconds as well.", level = 1 },
            { type = "list_item", text = "Hunter Pets will now benefit from equipped gear on the Hunter that reduces the chance to be dodged or parried.", level = 1 },
            { type = "list_item", text = "Swapping Rapid Killing to Lock and Load now prevents the use of Lock and Load for 60 seconds.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "The cooldown of Cold Snap has been reduced to 5 minutes (was 10 minutes).", level = 1 },
            { type = "list_item", text = "Fire Mage Tier 2.5 4-piece bonus decreased to 15% (was 20%).", level = 1 },
            { type = "list_item", text = "Fire Mage Ruins of Ahn’Qiraji 3-piece set bonus decreased to 15% (was 20%).", level = 1 },
            { type = "list_item", text = "Living Bomb now has an additional line of text that reads: “Living Bomb benefits from all talents and effects that trigger from or modify Scorch” allowing ticks of Living Bomb and the Explosion to apply Fire Vulnerability if talented.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Tier 2.5 Holy Paladin set 4-set bonus has been updated – Your heals on your Beacon of Light target also heal the nearest friendly injured target for 90% as much (was 30%).", level = 1 },
            { type = "h3", text = "November 26, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Chronoboon Displacer", level = 0 },
            { type = "list_item", text = "Items that share exclusivity with world buffs (Horn of the Dawn, Songflower Seed, Shimmering Globe, Overseer’s Anvil, “Defective” Magic 8-Ball, Firewater Cauldron (stacking change only), and Spirit Conch):", level = 1 },
            { type = "list_item", text = "Will no longer be removed if the person with the consumable leaves raid.", level = 2 },
            { type = "list_item", text = "Will extend the duration of the appropriate world buff instead of replacing it.", level = 2 },
            { type = "list_item", text = "Now stack up to 5.", level = 2 },
            { type = "list_item", text = "Known issue: these consumable items list their duration as Until Cancelled instead of 1 or 2 hours. That will be corrected in another hotfix.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Improved Moonfire now correctly increases the damage of Starfall.", level = 1 },
            { type = "list_item", text = "Improved Moonfire and Moonfury no longer affect base damage of their associated spells.", level = 1 },
            { type = "list_item", text = "Improved Moonfire and Moonfury now affect the entire damage of their associated spells.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Tranquilizing Shot no longer has a minimum range.", level = 1 },
            { type = "list_item", text = "Trueshot Aura will now grant the Marksmanship Hunter using it 100/150/200 additional ranged attack power (was 50/75/100).", level = 1 },
            { type = "list_item", text = "Melee T2.5 set 2-piece bonus now increases Wyvern Strike damage over time by 50%, and increases the maximum focus of your pet by 50 (was Increases Wyvern Strike damage over time by 50%).", level = 1 },
            { type = "list_item", text = "Melee T2.5 set 4-piece bonus now increases the impact damage of Mongoose Bite and all Strikes by 15% (was 10%).", level = 1 },
            { type = "list_item", text = "Beast Mastery rune now increases your pet’s damage and health by 15% (was 10%).", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Shadow Priest T2.5 set -piece bonus now increases the damage of Mind Spike by 20% (was 30%).", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "5 damage set 2-piece bonus will now only affect Saber Slash and Mutilate (was Sinister Strike and Saber Slash).", level = 1 },
            { type = "list_item", text = "5 tank set 2-piece bonus will now persist for 10 seconds after using Main Gauche (was tied to having the Parry buff active, and fell off when an attack was parried).", level = 1 },
            { type = "list_item", text = "The Attack Power ratio on Instant Poison with Deadly Brew has been increased to 5% (was 3%).", level = 1 },
            { type = "list_item", text = "Slaughter from the Shadows Ambush and Backstab increased against non-players increased to 60% (was 50%).", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "5 Enhancement 2-piece bonus that increases the damage of Stormstrike and Lava Lash by 50%, is now twice as effective for 2-handed weapons.", level = 1 },
            { type = "list_item", text = "5 Enhancement 4-piece bonus now causes your Stormstrike, Lava Lash, and Lava Burst critical strikes to burn your target for 30% of the damage done over 4 seconds (was only Stormstrike and Lava Lash).", level = 1 },
            { type = "list_item", text = "Ruins of Ahn’Qiraj 3-piece set will now correctly increase the damage of Lava Burst from Overload.", level = 1 },
            { type = "list_item", text = "5 Enhancement 4-piece bonus will now correctly work with Off-hand Stormstrike.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Haunt’s increase to Shadow damage over time effects increased to 40% (was 20%).", level = 1 },
            { type = "list_item", text = "Haunt now correctly has a return animation.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "November 25, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Items", level = 0 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Main Gauche now increases Sinister Strike threat generated by 50% (was 100%).", level = 1 },
            { type = "h3", text = "November 22, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Samantha Swifthoof will no longer patrol during the Bloodmoon Event in Strangelthorn Vale.", level = 0 },
            { type = "list_item", text = "The Ahn’Qiraj War Commendation World Buff consumables will now only apply only the Dragonslayer, Warchief’s, and Zandalar buffs to pets, as intended.", level = 0 },
            { type = "list_item", text = "The world buff consumables from War Effort Commendations changed to cost 50 (was 100).", level = 0 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Kill Shot cooldown reduced to 12 seconds (was 15 seconds).", level = 1 },
            { type = "list_item", text = "Kill Shot bonus damage increased to be 20% higher than Aimed Shot (weapon damage component unchanged at 100% of weapon damage).", level = 1 },
            { type = "list_item", text = "Ahn’Qiraj ranged 2-piece bonus now decreases the cooldown on Kill Shot by 65% when targets are between 20% and 50% health (was 50% reduction).", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fixed an issue with the Temple of Ahn’Qiraj 4-piece Arcane set bonus for players who did not have the Regeneration or Mass Regeneration runes equipped.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Just a Flesh Wound now reduces your Dodge chance by half. Evasion still provides its full effect of +50% Dodge.", level = 1 },
            { type = "list_item", text = "Just a Flesh Wound now reduces physical damage taken by 30% (was 20%), plus an additional 1% per 12 Defense above 300.", level = 1 },
            { type = "list_item", text = "Threat generated from Unfair Advantage has been increased by 50%, to compensate for it triggering less often.", level = 1 },
            { type = "list_item", text = "Main Gauche now generates 300% threat on impact (was 100%).", level = 1 },
            { type = "list_item", text = "Main Gauche now has a 15 second cooldown (was 20 seconds).", level = 1 },
            { type = "list_item", text = "Main Gauche now provides a 200% threat increase to Sinister Strike (was 150%).", level = 1 },
            { type = "list_item", text = "Main Gauche now provides the Sinister Strike threat increase for 30 seconds (was 10 seconds).", level = 1 },
            { type = "dev_note", text = "Since before the introduction of Rogue tanks, we’ve foreseen conditions where they become untouchable by melee attacks, and while this is core to the original Rogue tank fantasy, it’s not sustainable or healthy. We’re reducing avoidance and adding more consistency with damage reduction, so that Rogues can still tank, and we’re increasing the incentives on wearing Defensive gear while decreasing the incentives for wearing damage gear. Players can use Main Gauche in situations where they feel they want to actively mitigate incoming damage, instead of using it to maintain a buff. We’re planning to make additional adjustments to Rogue tanks, as well as to other classes and set bonuses in Ahn’Qiraj, prior to its release.", level = 2 },
            { type = "list_item", text = "Shaman", level = 1 },
            { type = "list_item", text = "Shield Mastery will now provide 4 Spell Power per point of Defense (was 2).", level = 2 },
            { type = "list_item", text = "Ahn’Qiraj Shaman tank set 2-piece bonus now also can trigger from Lava Burst and Molten Blast.", level = 2 },
            { type = "list_item", text = "Ahn’Qiraj Shaman tank set 4-piece bonus now also increases all threat generated by 20%, and all damage done by 10%.", level = 2 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "Haunt’s duration increased to 15 seconds (was 12 seconds).", level = 2 },
            { type = "list_item", text = "Unstable Affliction’s base damage (before spell power) increased by approximately 120% over its duration. Feedback damage from being dispelled remains the same.", level = 2 },
            { type = "list_item", text = "Ahn’Qiraj damage 4-piece bonus now increases Fire damage by 5% per stack, stacking up to 2 times (was 2% stacking 5 times).", level = 2 },
            { type = "list_item", text = "Ahn’Qiraj damage 2-piece now also increases Shadow Bolt damage by 10%, and now also allows Chaos Bolt to trigger the Improved Shadow Bolt talent.", level = 2 },
            { type = "list_item", text = "Ahn’Qiraj tank 4-piece now allows the effects of Demonic Sacrifice to persist while having a pet active, as long as the Warlock does not resummon the sacrificed pet. Warlocks may still only have one Demonic Sacrifice effect.", level = 2 },
            { type = "list_item", text = "Demonic Grace can be used while a Warlock has no pet active.", level = 2 },
            { type = "h3", text = "November 14, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Sylvan Vest now correctly has Stamina (was Strength).", level = 0 },
            { type = "h3", text = "November 12, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Fixed an issue where your sleeping dopplegangers could escape from Blackfathom Deeps and disrupt capital cities.", level = 0 },
            { type = "p", text = "October 30, 2024Season of Discovery" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Fixed a problem where the Druid PvP sets allowed multiple movement speed increases to stack. They no longer stack.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "When Chimera Shot is used with Serpent Sting, the extra effect now benefits properly from ranged weapon skills and gets the correct 10% critical strike chance increase from Sniper Training (was incorrectly 20%).", level = 1 },
            { type = "p", text = "October 15, 2024Season of Discovery" },
            { type = "list_item", text = "Tier 2 belt tokens no longer drop in Blackwing Lair. Prince Thunderaan still drops two belt tokens, and his single loot table for unique gear has been split in two.", level = 0 },
            { type = "dev_note", text = "The BWL change should result in players seeing more set pieces from other gear slots from Nefarian and the bonus chests. Prince Thunderaan’s split loot table now grants players an extra item every kill.", level = 1 },
            { type = "h3", text = "October 9, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Fixed an issue where Envenom was not increasing Instant Poison’s frequency unless the Rogue was also using Deadly Brew. It will now always increase the chance properly.", level = 0 },
            { type = "h3", text = "October 8, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Battlegrounds", level = 0 },
            { type = "list_item", text = "Arathi Basin and Warsong Gulch now award more Marks of Honor to the losing team when the match ends, based on the performance of the losing team.", level = 1 },
            { type = "list_item", text = "The losing team will always get 1 Mark of Honor, plus 1 extra for each flag capture in Warsong Gulch, or for each 600 resources earned in Arathi Basin.", level = 1 },
            { type = "list_item", text = "The winning team will now always receive 4 Marks of Honor.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fixed a problem with the Tier 2 Mage 6-piece damage set bonus that caused Fireball damage to not be increased unless the Mage was within 24 yards of the target. It will now work properly at any range.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Mind Spike now properly consumes charges from the Zandalarian Hero Charm.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The Venomous Totem will now properly increase the chance for Instant Poison to trigger from Deadly Brew (when no poison is applied).", level = 1 },
            { type = "p", text = "October 7, 2024Season of Discovery" },
            { type = "list_item", text = "Prince Thunderaan’s Squall now increases in damage every cast, his Chain Lightning should no longer fail to cast, the damage of his Lightning Cloud and Cyclonic Winds has been increased, and Lightning Cloud now afflicts damage more frequently.", level = 0 },
            { type = "list_item", text = "Players may now learn both Armorsmithing and Weaponsmithing at the same time.", level = 0 },
            { type = "list_item", text = "The Blackwing Lair Trials can no longer be disabled once Nefarian has been defeated.", level = 0 },
            { type = "p", text = "October 2, 2024Season of Discovery" },
            { type = "list_item", text = "Fixed an issue where the changing of the Bonus Weekly Affix didn’t align correctly with regional weekly reset times.", level = 0 },
            { type = "list_item", text = "Blackwing Lair", level = 0 },
            { type = "list_item", text = "Fixed an issue that would cause players killed in the first phase of the Nefarian fight to be ineligible for the bonus chest loot.", level = 1 },
            { type = "list_item", text = "Fixed an issue that occasionally prevented Nefarian from respawning after the raid wiped in Phase 2.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Fixed the trinket Cassandra’s Tome so that critical strike chance is increased every time Penance heals or deals damage (was the first per cast), Holy Nova will always consume a charge, even if it only heals, and Circle of Healing will now benefit from the increased critical strike chance and consume the effect when it does.", level = 1 },
            { type = "list_item", text = "Inner Focus now properly increases the critical strike chance of Circle of Healing.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The Static Shock rune no longer requires multiple players to obtain.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Fixed an issue with the tooltips on Booming Voice and Thunder Clap not updating to the intended functionality.", level = 1 },
            { type = "p", text = "October 1, 2024Season of Discovery" },
            { type = "list_item", text = "Blackwing Lair", level = 0 },
            { type = "list_item", text = "Cloak of Draconic Might and Essence Gatherer have been updated to their intended item level 75 (was item level 70).", level = 1 },
            { type = "list_item", text = "For Cloak of Draconic Might, this increased its armor and stats slightly.", level = 2 },
            { type = "list_item", text = "For Essence Gatherer, this increased its damage and stats slightly.", level = 2 },
            { type = "list_item", text = "Molten Core", level = 0 },
            { type = "list_item", text = "Shazzrah will no longer create two clones on Heat 3.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fixed an issue where the tier 1 6-piece armor set bonus was cancelling Mage Armor and Molten Armor buffs when the Mage traveled between zones and instances.", level = 1 },
            { type = "list_item", text = "Players are now able to restart “Essence of Fire” quest after abandoning it. Additionally, “Essence of Fire” can be picked up from Jennea Cannon or Oran Snakewrithe if previously abandoned, so long as players retain an item from that quest.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Doan Karhan can now be spoken to outside of Demon Fall Canyon regardless of which step of “The Final Test” the player is on.", level = 1 },
            { type = "list_item", text = "Abandoning “The Final Test” won’t destroy the Scythe of Chaos now.", level = 1 },
            { type = "h3", text = "September 30, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Losses in Warsong Gulch and Arathi Basin again award 1 Mark of Honor (was 2).", level = 0 },
            { type = "dev_note", text = "We’ve ended this experiment, as it provided too much incentive to lose quickly and get into another match.", level = 1 },
            { type = "list_item", text = "Blessing of Shirvallah should no longer buff the bad guys in Zul’Gurub.", level = 0 },
            { type = "list_item", text = "Addressed an issue that could cause the Cenarion Hold hitching post to be unusable during the hunter quest “Everyone Knows That Bugs Can’t Fly.”", level = 0 },
            { type = "list_item", text = "Blackwing Lair", level = 0 },
            { type = "list_item", text = "Fixed an issue that occasionally prevented the Trials from triggering after a soft reset in Blackwing Lair.", level = 1 },
            { type = "list_item", text = "Vaelastrasz the Corrupt", level = 1 },
            { type = "list_item", text = "Players’ own bonus damage modifiers will no longer amplify the damaging effects of Burning Adrenaline.", level = 2 },
            { type = "p", text = "September 27, 2024Season of Discovery" },
            { type = "list_item", text = "The Druid weapon Gla’sir will now pick damage targets of its damage effect based on the target’s location instead of the Druid’s own location. The range for the healing effect has been increased to 40 yards.", level = 0 },
            { type = "list_item", text = "Fixed an interaction issue with Tidal Waves Shaman rune and Chain Heal. Chain Heal will no longer sometimes not generate a charge of Tidal Waves.", level = 0 },
            { type = "list_item", text = "The quest “The Price of Hope” is no longer required to be completed to start the quest “Our Wayward Friend” at Katherine the Pure to start the Horn of Lordaeron.", level = 0 },
            { type = "list_item", text = "Blackwing Lair", level = 0 },
            { type = "list_item", text = "Victor Nefriendius now despawns during the Razorgore encounter.", level = 1 },
            { type = "list_item", text = "Fixed an issue that sometimes prevented the first door in Blackwing Lair from opening after wiping on Broodlord Lashlayer.", level = 1 },
            { type = "list_item", text = "Fixed an issue that allowed Nefarian’s initial Shadow Flame spell to affect player pets.", level = 1 },
            { type = "p", text = "September 11, 2024Season of Discovery" },
            { type = "list_item", text = "Crimson Tempest can no longer be used unless the primary target is within melee range.", level = 0 },
            { type = "p", text = "August 23, 2024Season of Discovery" },
            { type = "list_item", text = "Firelands Embers and Emerald Chips now stack to 2500.", level = 0 },
            { type = "dev_note", text = "Hang on to these currencies, as new items will be made available for purchase in the next major patch.", level = 1 },
            { type = "list_item", text = "Nightmare Incursion boss experience has been reduced by 50%.", level = 0 },
            { type = "list_item", text = "Bosses in Molten Core should no longer spin around and face random raid members on higher Heat difficulties.", level = 0 },
            { type = "h3", text = "August 20, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "The Wild Strikes aura, which has been limited to the Druid’s party within 20 yards, is now raid-wide with a 100-yard radius.", level = 1 },
            { type = "dev_note", text = "For a time, the tooltip will still say that it is restricted to the party. We intend to correct that in the next major patch.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frozen Orb damage now correctly benefits from the Spell Power rune.", level = 1 },
            { type = "p", text = "August 15, 2024Season of Discovery" },
            { type = "list_item", text = "The following spells will no longer incorrectly reset their cooldowns after a boss is defeated:", level = 0 },
            { type = "list_item", text = "Feral Spirits (Shaman)", level = 1 },
            { type = "list_item", text = "Icy Veins (Mage)", level = 1 },
            { type = "list_item", text = "Portal of Summoning (Warlock)", level = 1 },
            { type = "list_item", text = "Berserk (Druid)", level = 1 },
            { type = "list_item", text = "Ancestral Guidance (Shaman)", level = 1 },
            { type = "list_item", text = "Hand of Sacrifice (Paladin)", level = 1 },
            { type = "list_item", text = "Avenging Wrath (Paladin)", level = 1 },
            { type = "list_item", text = "Dispersion (Priest)", level = 1 },
            { type = "list_item", text = "Homunculi (Priest)", level = 1 },
            { type = "list_item", text = "Eye of the Void (Priest)", level = 1 },
            { type = "list_item", text = "Pain Suppression (Priest)", level = 1 },
            { type = "list_item", text = "Shadowfiend (Priest)", level = 1 },
            { type = "list_item", text = "Enraged Regeneration (Warrior)", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "100% crit chance Fire Blasts from Overheat will no longer count towards Combustion’s 3 crits, and will no longer increase the stacks of Combustion.", level = 1 },
            { type = "h3", text = "August 13, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The % increase to player health that is present in Warsong Gulch and Arathi Basin is now also active in Alterac Valley.", level = 0 },
            { type = "list_item", text = "Items", level = 0 },
            { type = "list_item", text = "Shard of the God’s summoned minion now has a 20-yard cone (was 40 yards) and will spend the first 3 seconds of its summon to run into range of a target.", level = 1 },
            { type = "list_item", text = "Quests", level = 0 },
            { type = "list_item", text = "“Stave of the Ancients\" Demon NPCs will now respawn much more quickly.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "The bonus on Moonkin Form that increases Moonfire (and Sunfire) periodic damage now increases it by 100% (was 50%).", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Immolation Trap now has a 7.5 second duration, but still deals the same amount of damage as it did over 15 seconds. This allows it to deliver all its damage before its cooldown is available again.", level = 1 },
            { type = "list_item", text = "Raptor Fury now lasts 30 seconds and increases Raptor Strike damage by 15% per application (was 10%).", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane Barrage now has its mana cost correctly reduced by Clearcasting.", level = 1 },
            { type = "list_item", text = "Pyroblasts from Hot Streak will no longer consume Clearcasting.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Divine Light now has an 8 second cooldown.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Main Gauche will now correctly be consumed when you Parry an attack, regardless of the type of enemy you are fighting.", level = 1 },
            { type = "list_item", text = "Focused Attacks now refunds 2 Energy from critical strikes (was 3 Energy).", level = 1 },
            { type = "list_item", text = "Envenom’s erroneous spell power ratio has been removed.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Shamanistic Rage now grants the rest of the party and raid 18% of the mana granted to the Shaman (was 10%).", level = 1 },
            { type = "dev_note", text = "This change was made to better equalize mana provided to parties and raids between horde and alliance.", level = 2 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "Warlock pets will now correctly benefit from Fel Armor’s increase to their master’s spell power.", level = 2 },
            { type = "h3", text = "August 7, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Heart of the Lion once again has a 100 yard range.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "The Focused Rage rune will now correctly reduce the cost of Meathook by 3.", level = 1 },
            { type = "h3", text = "August 5, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Each side of the Poacher’s cave tunnel between Searing Gorge and Burning Steppes now has an independent cooldown, allowing curious players a quick return option. Smoke asphyxiation still prevents more-frequent usage than twice an hour.", level = 0 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Moonkin Form now also decreases all threat generated by Nature and Arcane spells cast by the Druid by 30%.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "[ With scheduled maintenance ] The Hunter T.N.T. rune now increases Explosive Trap initial damage and Immolation Trap periodic damage based on 25% of the Hunter’s Attack Power (was 50%). It also now uses the higher of melee and ranged Attack Power (was always melee Attack Power).", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fixed an issue where the Mage Healer 2-piece Molten Core set bonus did not working properly. The benefits of the Temporal Beacon will now work properly during the last 6 seconds of its duration when used with this set.", level = 1 },
            { type = "list_item", text = "Fixed an issue where the healing from Mage Regeneration was not increased by the effects of Mage Arcane Blast.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "[ With scheduled maintenance ] Retribution Paladins in Season of Discovery now gain 6% threat reduction per rank of the Vengeance talent, but this threat reduction is disabled while Righteous Fury is active.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Homunculi will now be less aggressive in seeking nearby targets to fight that the Priest is not in combat with.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The Rogue 6-piece set can no longer trigger incorrectly from Sebacious Poison.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Khonsu should now always speak the correct line when players are victorious.", level = 1 },
            { type = "h3", text = "August 1, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Molten Core", level = 0 },
            { type = "list_item", text = "Players can no longer line of sight Flamewaker Priests from Sulfuron Harbinger or outrange them to prevent the cast from Dark Mending, it must be interrupted!", level = 1 },
            { type = "list_item", text = "Adjusted the recast time and cooldown of Dark Mending so that players can interrupt more sufficiently.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The Spirit Wolves summoned by Feral Spirits should now display all four of their active abilities on their pet bar.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "The Tier 1 Warrior 2-piece set bonus, Tactician, will now correctly reduce the cost of Meathook.", level = 1 },
            { type = "h3", text = "July 31, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Further increased drop chances of Libram of Resilience from various sources in the world.", level = 0 },
            { type = "list_item", text = "Added a chance for Libram of Voracity, Rapidity, and Resilience to appear in the Damaged Undermine Supply Crates purchased with Tarnished Undermine Reals.", level = 0 },
            { type = "list_item", text = "Essence of the Pure Flame will now show its reflect damage in the combat log.", level = 0 },
            { type = "list_item", text = "Hydraxian Coronation now binds the target piece of gear.", level = 0 },
            { type = "list_item", text = "The Alliance quest “End of the Dark Horde” is now given by Master Mathias Shaw (was given by General Marcus Jonathan).", level = 0 },
            { type = "list_item", text = "Overcharged rune can now be obtained by those that previously completed the discovery but didn’t get the rune.", level = 0 },
            { type = "list_item", text = "Fine Flarecore Gloves are no longer class restricted.", level = 0 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Kill Shot will now have increased ranged with the Hawk Eye talent.", level = 1 },
            { type = "list_item", text = "Hunters can no longer place multiples of the same trap by unequipping Trap Launcher and placing the trap.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "The Elemental Tier 1 6-piece bonus will now correctly refresh Flame Shock to 18 seconds if Burn is engraved.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Mages’ Balefire Bolt can no longer damage targets affected by Banish. They will be Immune.", level = 1 },
            { type = "h3", text = "July 30, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Shard of the Scale and Flame’s set bonus is now activated by all spells (was only direct healing and spell damage).", level = 0 },
            { type = "list_item", text = "Anathema and Benediction can now correctly be swapped after a one minute cooldown has passed.", level = 0 },
            { type = "list_item", text = "Molten Core", level = 0 },
            { type = "list_item", text = "Fixed an issue that prevented Shazzrah from casting Gate of Shazzrah twice in a row on Heat 3.", level = 1 },
            { type = "list_item", text = "Ragnaros no longer submerges twice on Heat 1.", level = 1 },
            { type = "list_item", text = "Baron Geddon now casts Armageddon at 5% on Heat 1 (was 10%).", level = 1 },
            { type = "list_item", text = "Baron Geddon now casts 2 Living Bombs at a time on Heat 2 (was 3).", level = 1 },
            { type = "list_item", text = "Living Bomb no longer leaves Living Fallout pools on Heat 1.", level = 1 },
            { type = "list_item", text = "Flamewaker Protectors now cast Dominate Mind much less frequently.", level = 1 },
            { type = "list_item", text = "Maximized the cast and recast times of several dispel mechanics.", level = 1 },
            { type = "list_item", text = "Damage done to self with spells such as Hellfire is no longer increased by the low Fire Resistance effects on Heat levels 2 and 3 in Molten Core.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Mass Regeneration range for detecting allies to heal increased to 43 yards (was 30), to eliminate the situation where it was possible to heal others who were outside the range for your heal to apply to yourself.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Homunculi now cast and stack Sunder Armor relative to the rank they would have if they were a Warrior of their level.", level = 1 },
            { type = "dev_note", text = "This takes the place of their casting Degrade previously. Now a friendly Warrior can refresh a Homunculi’s 5 stack of Sunder Armor. The strength of this debuff at max level is unchanged.", level = 2 },
            { type = "list_item", text = "Spirit of the Redeemer will now correctly put Pain Suppression and Dispersion on a two-minute cooldown (was incorrectly 5 minutes).", level = 1 },
            { type = "h3", text = "July 29, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Players who have the 18-slot version of the Bottomless Bag may now exchange the bag or the Pattern for the 20-slot version at Rix Xizzix in Booty Bay.", level = 0 },
            { type = "list_item", text = "Players who have killed Magmadar but are unable to douse the Rune of Kress can now swap the Heat difficulty back and forth and should find you can now douse the Rune.", level = 0 },
            { type = "list_item", text = "Lava Surgers in Molten Core will no longer spawn once Ragnaros has been defeated.", level = 0 },
            { type = "list_item", text = "Fixed an issue with many of the class dungeon set bonuses. They can now only be triggered by abilities, and not by item use.", level = 0 },
            { type = "list_item", text = "Ragnaros is no longer immune to Paladins’ Hand of Reckoning.", level = 0 },
            { type = "list_item", text = "Fixed a bug interrupting eating or drinking when near a graveyard.", level = 0 },
            { type = "list_item", text = "Fixed a bug where the incorrect version of Quel’Serrar could appear in this version of the game.", level = 0 },
            { type = "list_item", text = "[With weekly restarts] The increased damage taken for low Fire Resistance in Molten Core on Heat 2 and Heat 3 has been reduced but is still extremely dangerous. Characters who are at 30 resistance lower than intended should now expect to take about 3 times normal damage (was guaranteed fatal).", level = 0 },
            { type = "dev_note", text = "This is intended to allow players who are dependent on Resistance Totems or Paladin Auras to have a chance to survive if briefly not within the range of those effects.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "[With weekly restarts] Entrapment now triggers a diminishing return as a Root effect on players each time it is applied. Subsequent durations will be halved and then quartered in duration, and then the target will become immune for 30 seconds.", level = 1 },
            { type = "list_item", text = "Fixed a bug that prevented Hunters from being able to interact with the four demons involved in the Rhok’delar quest chain.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Fixed an issue where re-speccing did not remove Divine Spirit appropriately.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The 6-piece Tier 1 bonus no longer puts Vanish on cooldown.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "You can no longer have Burn and Way of Earth active at the same time by using Rockbiter Rank 3.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Shadowflame will no longer be overwritten by Improved Shadow Bolt.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "The Warrior 2-piece Tier 1 bonus Tactician will no longer be consumed if the spell cast was a free Blood Surge Slam.", level = 1 },
            { type = "h3", text = "July 25, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Increased the number of Firelands Invader, Obsidian Reaver, and Obsidian Surger spawns for the Blackrock Eruption event across Searing Gorge.", level = 0 },
            { type = "list_item", text = "The Might of Stormwind buff will now appear properly in the tooltip when a Chronoboon is used.", level = 0 },
            { type = "list_item", text = "Items", level = 0 },
            { type = "list_item", text = "Devilcore Leggings and Devilcore Gloves patterns can now drop from additional sources other than King Mosh.", level = 1 },
            { type = "list_item", text = "All of the revamped or new Molten Core items that were strictly Unique are now Unique-Equipped to allow master looters to hold these items during raids.", level = 1 },
            { type = "list_item", text = "Season of Discovery versions of recipes should be available again from their trainers, making turn-ins for professions quests possible.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Rewind Time can no longer be cast if the target will not benefit from its healing.", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Priests who don’t have the Divine Spirit talent learned are now prevented from casting higher ranks of Divine Spirit and Prayer of Spirit.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "The cooldown on Rogue Shuriken Toss has been reduced to 20 seconds (was 30 seconds).", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Shadowflame will no longer be overwritten by Improved Shadow Bolt.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Last Stand cooldown reduced to 3 minutes.", level = 1 },
            { type = "h3", text = "July 24, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Items", level = 0 },
            { type = "list_item", text = "Burning Essences will now always drop from the Dark Coffer in Blackrock Depths.", level = 1 },
            { type = "list_item", text = "Librams of Resilience now have an additional chance to drop from certain bosses in Blackrock Depths and Blackrock Spire.", level = 1 },
            { type = "list_item", text = "When Might of Stormwind is restored from a Chronoboon, the buff will now appear properly in the tooltip and it will now correctly apply to the player’s pet.", level = 1 },
            { type = "list_item", text = "You may now mount while Gift of Gob is active.", level = 1 },
            { type = "list_item", text = "Darkmoon Card: Sandstorm will now correctly hit enemies that are within line of sight, and not hit enemies that are out of line of sight.", level = 1 },
            { type = "list_item", text = "Darkmoon Card: Decay internal cooldown increased to 3 seconds.", level = 1 },
            { type = "list_item", text = "Pix Xizzix now offers the Drakestone caster offhands for 50 Undermine Real each.", level = 1 },
            { type = "dev_note", text = "While we don’t intend to put everything of this nature onto the vendor, the offhands from Sunken Temple felt right to us.", level = 2 },
            { type = "list_item", text = "Professions", level = 0 },
            { type = "list_item", text = "Mixology now always gives at least 2 potions as intended.", level = 1 },
            { type = "list_item", text = "Professions with adjusted level requirements for Expert and Artisan ranks have been returned to their original level requirements.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Idol of the Moon tooltip updated for accuracy and clarity. The item’s effect is unchanged.", level = 1 },
            { type = "list_item", text = "Idol of the Moon now correctly applies to Starfall and Sunfire.", level = 1 },
            { type = "list_item", text = "Idol of Brutality now correctly applies to Mangle (Bear).", level = 1 },
            { type = "list_item", text = "Idol of Ferocity no longer incorrectly discounts Mangle (Bear).", level = 1 },
            { type = "list_item", text = "Idol of the Dream now correctly affects Swipe (Cat).", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Players can now have only one Mana Shield active at a time. If an equal or higher rank of Mana Shield is cast on the target, it will overwrite the previous Mana Shield.", level = 1 },
            { type = "list_item", text = "Fixed an issue with Rewind Time where refreshing Temporal Beacon on a target after that target took damage, which would make any damage taken before the refresh not get healed by Rewind Time.", level = 1 },
            { type = "list_item", text = "Improved Arcane Missiles now also grants 20% spell pushback resistance per talent point to Regeneration and Mass Regeneration and 14% spell pushback resistance per talent point to Arcane Blast.", level = 1 },
            { type = "list_item", text = "Mass Regeneration will now refresh Temporal Beacon each time it heals a target, instead of just when initially hitting a target.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Blessing of Sanctuary and Greater Blessing of Sanctuary no longer stack.", level = 1 },
            { type = "list_item", text = "Libram of the Consecrated is no longer be removed by ticks of Hallowed Ground.", level = 1 },
            { type = "list_item", text = "Malleable Protection’s version of Divine Protection now correctly has a 5-minute cooldown.", level = 1 },
            { type = "list_item", text = "Malleable Protection’s version of Divine Protection will now correctly share a cooldown between its two ranks and Divine Shield.", level = 1 },
            { type = "list_item", text = "The cooldown on Paladin Avenger’s Shield has been reduced to 15 seconds (was 30 seconds), and the duration of its movement Snare effect has been reduced to 5 seconds (was 10 seconds).", level = 1 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Juju Might no longer erroneously benefits from the Improved Inner Fire talent.", level = 1 },
            { type = "list_item", text = "Vampiric Embrace heal range increased from 30 yards to 40 yards.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Rampage now appears as a buff when activated.", level = 1 },
            { type = "h3", text = "July 22, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Devilsaur gauntlets should no longer require core leather. They now require 12 Devilsaur leather and 8 Essence of Fire in addition to their other existing mats. Devilsaur leggings should now require 20 Devilsaur leather and 10 Essence of fire in addition to their other mats.", level = 0 },
            { type = "list_item", text = "Made some improvements to the respawn rate of mobs and quest objects on Alcaz Island.", level = 0 },
            { type = "list_item", text = "The Chipped Drakefire Amulet and Valor of Azeroth spell book are now available from Squire Rowe in Stormwind and Eitrigg in Orgrimmar for players who have completed the Onyxia quest chain.", level = 0 },
            { type = "list_item", text = "Gift of Gob will no longer cancel on stealth.", level = 0 },
            { type = "list_item", text = "Made some improvements to Bolvar Fordragon’s respawn time.", level = 0 },
            { type = "list_item", text = "Zor Lonetree’s wares are available while completing Rune discoveries.", level = 0 },
            { type = "list_item", text = "Corrected the stats on the Old Guard Retaliator.", level = 0 },
            { type = "list_item", text = "Darkmoon Card: Sandstorm will no longer ignore line-of-sight.", level = 0 },
            { type = "list_item", text = "Quests from Zalgo the Explorer no longer erroneously give Zandalar Tribe reputation. They now give reputation for the Emerald Wardens up to friendly 5999/6000. These quests will always reward the same amount of reputation based on level.", level = 0 },
            { type = "list_item", text = "All runes sold by the Emerald Wardens quartermasters no longer require reputation to purchase. Catnip and Wolfshead Trophy no longer require Emerald Wardens reputation to purchase.", level = 0 },
            { type = "list_item", text = "“The Lost Tablets of Mosh’aru” should now be completable if you’ve previously completed “The God Hakkar”.", level = 0 },
            { type = "list_item", text = "In Nightmare Incursions, Ghamoo-Raja will now leash and no longer has infinite range on certain attacks.", level = 0 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Explosive Shot will no longer ignore line-of-sight.", level = 1 },
            { type = "list_item", text = "Fixed an issue with Lethal Shots that made it stop working after death until the Hunter re-equips their ranged weapon.", level = 1 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Presence of Mind will no longer be removed from the Mage without successfully casting Chronostatic Preservation.", level = 1 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "When the Carnage rune is engraved, Crimson Tempest will now correctly apply Carnage to all enemies struck by the DoT.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Clearcasting will now correctly be consumed if you have 5 stacks of Maelstrom Weapon and you cast a non-Maelstrom Weapon empowered spell.", level = 1 },
            { type = "list_item", text = "Totem of Earthen Vitality will no longer activate when the Shaman is merely struck.", level = 1 },
            { type = "list_item", text = "Overcharged will no longer ignore line-of-sight.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Master Channeler’s Drain Life will no longer prematurely end vs. large enemies like Lord Kazzak.", level = 1 },
            { type = "list_item", text = "Mark of Chaos will no longer fail to refresh if the target has Curse of the Elements or Curse of Shadows active on them.", level = 1 },
            { type = "list_item", text = "Curse of the Elements and Curse of Shadows will now return ‘A more powerful spell is already active.’", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Bosses in dungeons are now always immune to Meathook as intended.", level = 1 },
            { type = "h3", text = "July 17, 2024" },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "The tooltip for the Draconic Infused Emblem is now correct. The spell effect is not changed.", level = 0 },
            { type = "list_item", text = "Blackrock Eruption", level = 0 },
            { type = "list_item", text = "The Drained of Blood aura from the Stranglethorn Vale PvP event is now applied when participating in the Blackrock Mountain PvP event. This applies to players exiting instances in Blackrock Mountain.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Flame Wrath has been redesigned with a lower spell power ratio on the Thorns portion of the proc and an internal cooldown for Feral Druids.", level = 1 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Trap Launcher will no longer augment Frost Trap.", level = 1 },
            { type = "dev_note", text = "A Trap Launcher version of Frost Trap has only existed in versions of WoW in which mobility and freedom effects were more plentiful. Without them, the safety and agency a 9-15 second ranged Frost Trap grants Hunters is simply too much. We’re making it so that Hunters either need to put themselves at risk in order to place a Frost Trap or have someone engage on them to trigger it.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Conjure Water Rank 7 will now create 20 water per cast. The tooltip may not reflect this change for a while.", level = 1 },
            { type = "list_item", text = "All ranks of Mana Shield will no longer stack when Advanced Warding is engraved.", level = 1 },
            { type = "list_item", text = "All ranks of Advanced Warding’s Mana Shield are now canceled when the rune is unequipped or when someone absorbs damage and the caster no longer has the rune equipped.", level = 1 },
            { type = "list_item", text = "All ranks of Mana Shield are removed when the Advanced Warding Rune is equipped.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Burn will now persist through death and not require you to recast Flametongue Weapon again.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Fel Rift spawn rates have increased.", level = 1 },
            { type = "list_item", text = "The chance of finding Legion Portal Tuners and associated tools has increased.", level = 1 },
            { type = "list_item", text = "Rune of Decimation is now guaranteed from an overcharged portal.", level = 1 },
            },
        },
