            { type = "list_item", text = "Fixed a bug where Blood Tap with Death Siphon could provide an unintended extra invisible rune.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Summon Gargoyle will no longer cancel casts of Gargoyle Strike and will now smoothly cast them back-to-back.", level = 2 },
            { type = "list_item", text = "Summon Gargoyle’s Gargoyle Strike attack can no longer go below a 0.5 second cast time.", level = 2 },
