        ["2026-06-03-mists-of-pandaria-classic-the-siege-of-orgrimmar-now-live-97d554bca8"] = {
            id = "2026-06-03-mists-of-pandaria-classic-the-siege-of-orgrimmar-now-live-97d554bca8",
            post_key = "97d554bca8",
            title = "Mists of Pandaria Classic: The Siege of Orgrimmar Now Live",
            category = "Blogs (EU)",
            timestamp = 1780499392,
            url = "https://news.blizzard.com/en-gb/article/24264421/mists-of-pandaria-classic-the-siege-of-orgrimmar-update-arrives-2-june",
            content = {
            { type = "p", text = "Azeroth's heroes have stood against the Thunder King, yet a darker storm now gathers in Garrosh Hellscream. With the Vale of Eternal Blossoms corrupted and Orgrimmar in chaos, the Warchief must be stopped before all are dragged into darkness." },
            { type = "p", text = "Get ready for new content and features, including a new zone—Timeless Isle, a new multi-part raid—Siege of Orgrimmar, five new World Bosses, the final push for the Legendary Cloak, Proving Grounds, and more!" },
            { type = "h2", text = "AT A GLANCE" },
            { type = "list_item", text = "New Zone: Timeless Isle", level = 0 },
            { type = "list_item", text = "New Faction: Emperor Shaohao", level = 0 },
            { type = "list_item", text = "Wrathion's Final Quests for the Legendary Cloak", level = 0 },
            { type = "list_item", text = "New Raid: Siege of Orgrimmar", level = 0 },
            { type = "list_item", text = "Five New World Bosses", level = 0 },
            { type = "list_item", text = "PvP Season 14", level = 0 },
            { type = "list_item", text = "Celestial Dungeon Season 3", level = 0 },
            { type = "list_item", text = "Season 3 Challenge Mode Dungeons: Diamond Mode", level = 0 },
            { type = "list_item", text = "Proving Grounds", level = 0 },
            { type = "hr" },
            { type = "h2", text = "UNCOVER THE MYSTERIOUS TIMELESS ISLE AND CLAIM ITS TREASURES" },
            { type = "p", text = "A mysterious island, long lost to time, has emerged from the mists off the eastern coast of the Jade Forest. The Timeless Isle is teeming with powerful enemies, hidden treasures, rare creatures, and unpredictable events that will test even the boldest explorers." },
            { type = "image", width = 630, height = 420, u = 0.615234, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-03-mists-of-pandaria-classic-the-siege-of-orgrimmar-now-live-97d554bca8\\image-1.jpg" },
            { type = "p", text = "To reach the Timeless Isle, adventurers can travel from their faction's shrine in the Vale of Eternal Blossoms." },
            { type = "hr" },
            { type = "h2", text = "EARN REPUTATION WITH EMPEROR SHAOHAO FOR NEW REWARDS" },
            { type = "p", text = "The Timeless Isle introduces a new reputation faction: Emperor Shaohao. Reputation is earned primarily through combat—especially by slaying Yaungol across the island." },
            { type = "p", text = "A new currency, Timeless Coins, can be collected and spent on a wide range of rewards, including the Heavenly Golden Cloud Serpent account-wide flying mount, Harmonious Porcupette battle pet, and powerful vanity items. Visit Mistweaver Ku on the eastern side of the Celestial Court to browse the full catalog of offerings." },
            { type = "hr" },
            { type = "h2", text = "CLAIM YOUR LEGENDARY CLOAK AS THE QUESTLINE COMES TO AN END" },
            { type = "p", text = "Wrathion's long‑running questline reaches its conclusion. Heroes who have stood with the Black Prince throughout the Pandaren campaign can continue their journey on the Timeless Isle." },
            { type = "p", text = "Meet Wrathion at the Tavern in the Mists in the Veiled Stair to complete his final tasks—and bring down Garrosh Hellscream in the Siege of Orgrimmar—to forge a Legendary cloak and unlock access to Ordos, Fire‑God of the Yaungol." },
            { type = "hr" },
            { type = "h2", text = "PUT AN END TO GARROSH IN THE SIEGE OF ORGRIMMAR RAID" },
            { type = "p", text = "The Siege of Orgrimmar is a sprawling, two‑part raid that takes players from the scarred ruins of the Vale of Eternal Blossoms to the heart of the Horde's capital, Orgrimmar in Durotar." },
            { type = "p", text = "When: 4 June, 23:00 BST globally" },
            { type = "p", text = "Garrosh's actions have left devastation in his wake. Heroes must first confront the consequences of the corruption in the Vale—where the Heart of Y'Shaarj has poisoned the land—before pushing through Orgrimmar's defenses to face the Warchief himself." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-03-mists-of-pandaria-classic-the-siege-of-orgrimmar-now-live-97d554bca8\\image-2.jpg" },
            { type = "h3", text = "Prepare to Face New Raid Encounters and their Bosses" },
            { type = "p", text = "Vale of Eternal Sorrows" },
            { type = "p", text = "Venture through the scarred Vale of Eternal Blossoms, exploring unearthed mogu ruins to discover the source of the destruction." },
            { type = "list_item", text = "Immerseus", level = 0 },
            { type = "list_item", text = "The Fallen Protectors", level = 0 },
            { type = "list_item", text = "Norushen", level = 0 },
            { type = "list_item", text = "Sha of Pride", level = 0 },
            { type = "p", text = "Gates of Retribution" },
            { type = "p", text = "War has come to the gates of Orgrimmar, as Alliance forces and the Darkspear Rebellion seek revenge against Garrosh Hellscream." },
            { type = "list_item", text = "Galakras", level = 0 },
            { type = "list_item", text = "Iron Juggernaut", level = 0 },
            { type = "list_item", text = "Kor'kron Dark Shaman", level = 0 },
            { type = "list_item", text = "General Nazgrim", level = 0 },
            { type = "p", text = "The Underhold" },
            { type = "p", text = "Within a secret Kor'kron base carved into the sweltering caverns beneath Orgrimmar, Garrosh is assembling his ultimate army." },
            { type = "list_item", text = "Malkorok", level = 0 },
            { type = "list_item", text = "Spoils of Pandaria", level = 0 },
            { type = "list_item", text = "Thok the Bloodthirsty", level = 0 },
            { type = "p", text = "Downfall" },
            { type = "p", text = "Wielding the dark power that lay dormant beneath Pandaria, Garrosh seeks to bring a new order to Azeroth. He must be stopped!" },
            { type = "list_item", text = "Siegecrafter Blackfuse", level = 0 },
            { type = "list_item", text = "Paragons of the Klaxxi", level = 0 },
            { type = "list_item", text = "Garrosh Hellscream", level = 0 },
            { type = "p", text = "For more details, read through our previously published overview." },
            { type = "hr" },
            { type = "h2", text = "TRAVEL TO THE TIMELESS ISLE TO TEST YOUR METTLE AGAINST WORLD BOSSES" },
            { type = "p", text = "The Timeless Isle is home to powerful world bosses tied to the trials of the August Celestials. Each encounter reflects the lessons Emperor Shaohao once faced—hope, wisdom, fortitude, and restraint—and challenges heroes to prove their worth through combat." },
            { type = "p", text = "Those who have earned Wrathion's Legendary Cloak may also ascend to face Ordos, a fiery demigod bound by ancient flame and suffering." },
            { type = "p", text = "Chi-Ji, The Red Crane" },
            { type = "p", text = "The trial of Chi-Ji is a test of hope. Uncertain of the future of his people, Emperor Shaohao sought out the great Red Crane. The Great Crane challenged Shaohao to find the hope within himself and cast off his uncertainty. Once the Sha of Doubt was vanquished, the Emperor became a beacon of hope for his people. To pass the trial of the Crane, warriors must believe in hope, even in the darkest of days." },
            { type = "p", text = "Yu'lon, The Jade Serpent" },
            { type = "p", text = "The trial of Yu'lon is a test of wisdom and faith. With omens of a bleak future floating through his mind, Emperor Shaohao climbed to the summit of Mount Neverest to seek the council of the Jade Serpent. Yu'lon urged Shaohao to cast off the dark emotions that plagued him, and through his trials, Emperor Shaohao would become one with the land. To pass the trial of the Serpent, warriors must be wise in their choices." },
            { type = "p", text = "Niuzao, The Black Ox" },
            { type = "p", text = "The trial of Niuzao is a test of bravery and fortitude. When Emperor Shaohao was overcome with fear, the Black Ox counseled him to face his fears directly. After a protracted battle with the Sha of Fear, the Emperor emerged victorious. To pass the trial of the Ox, warriors must be resolute in the face of overwhelming danger." },
            { type = "p", text = "Xuen, The White Tiger" },
            { type = "p", text = "The trial of Xuen is simultaneously a test of strength and restraint. When Xuen gave Emperor Shaohao a 10-foot pole and asked him to strike one of Xuen's warriors, the Emperor could not land a blow. For without restraint, anger and hatred run wild. To pass the trial of the Tiger, warriors must harness their power while burying their thoughts of violence." },
            { type = "p", text = "Ordos, Fire-God of the Yaungol" },
            { type = "p", text = "Ordos was once a shaman of the Yaungol who sacrificed himself to the flame, following the promises of the Fire Lords, to become a demigod. His flesh is eternally seared with fires, putting him in endless agony. Yaungol Fire-Keepers ritualistically set themselves ablaze to emulate the ascension of Ordos, and cast enchantments and prayers to ease his pain." },
            { type = "hr" },
            { type = "h2", text = "CLAIM NEW ARMOR AND REWARDS IN PVP SEASON 14" },
            { type = "p", text = "When: Week of 2 June, with each region's maintenance." },
            { type = "image", width = 720, height = 256, u = 0.703125, v = 1, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-03-mists-of-pandaria-classic-the-siege-of-orgrimmar-now-live-97d554bca8\\image-3.jpg" },
            { type = "p", text = "A new mount is available to combatants of all ranks." },
            { type = "list_item", text = "Winning 100 3v3 matches or 40 RBGs in Season 14 earns the Grievous Combatant achievement and awards the Vicious Saddle .", level = 0 },
            { type = "list_item", text = "For champions of the Alliance, the Vicious Saddle can be redeemed at Necrolord Sipe for either Reins of the Vicious War Steed or Reins of the Vicious Warsaber .", level = 1 },
            { type = "list_item", text = "For heroes of the Horde, redeem at Deathguard Netharian for either Horn of the Vicious War Wolf or Reins of the Vicious Skeletal Warhorse .", level = 1 },
            { type = "hr" },
            { type = "h2", text = "BEAR WITNESS IN SEASON 3'S CELESTIAL DUNGEONS WITH POWERFUL BUFFS" },
            { type = "p", text = "Garrosh's influence reaches far beyond Orgrimmar. His Kor'kron forces have seized control of Pandaria's dungeons, reinforcing bosses and tightening their grip with banners, empowered abilities, and brutal modifiers." },
            { type = "p", text = "To survive these escalating dangers, heroes can call upon the blessings of the August Celestials. When all four answer the call, the Celestial Witness buff grants increased power in Celestial Dungeons." },
            { type = "p", text = "The stars themselves will reshape in the sky to signify this immense moment." },
            { type = "list_item", text = "Celestial Witness : Witnessing the arrival of August Celestials infuses players with the Celestial Witness buff, increasing their Damage and Healing done, and reducing their damage taken for an extended period.", level = 0 },
            { type = "p", text = "Brave heroes aren't the only ones to get a powerful buff. Difficult enemies add to the complexity of play when they're empowered:" },
            { type = "list_item", text = "Glory to the True Horde : Creatures in the Celestial Dungeons will have their Damage and Health increased.", level = 0 },
            { type = "list_item", text = "Kor'kron Banners : Banners are now planted throughout the dungeons that empower nearby enemies.", level = 0 },
            { type = "list_item", text = "Periodically, a boss is influenced by Garrosh Hellscream and will use an ability based on one of his loyal followers from the Siege of Orgrimmar Raid:", level = 1 },
            { type = "list_item", text = "General Nazgrim, Wavebinder Kardis, or Siegecrafter Blackfuse will answer Garrosh's call to arms.", level = 2 },
            { type = "hr" },
            { type = "h2", text = "CHASE GLORY IN SEASON 3 CHALLENGE MODE DUNGEONS" },
            { type = "p", text = "As Season 2 closes with the release of the Siege of Orgrimmar, we usher in Season 3. Remarkable times will be cemented as Diamond—a tier above Platinum—and times are reflected in-game in the Challenge Mode menu." },
            { type = "p", text = "New Platinum Coin rewards have found their way to Jaelof Ironhart for Alliance champions, and Viktor Felhallow for defenders of the Horde!" },
            { type = "hr" },
            { type = "h2", text = "ENTER THE PROVING GROUNDS FOR SOLO ROLE-BASED CHALLENGES" },
            { type = "p", text = "The Proving Grounds offer a focused, repeatable solo challenge for heroes looking to sharpen their skills. Whether tank, healer, or damage dealer, each role faces tailored scenarios designed to test awareness, execution, and adaptability." },
            { type = "p", text = "Set within the Temple of the White Tiger, this new feature will provide a repeatable solo Scenario where level 90 players can test their mettle or try out different roles." },
            { type = "h3", text = "How to Enter the Proving Grounds to Begin Your Trials" },
            { type = "p", text = "To get started, you'll need to talk with an NPC in the Temple of the White Tiger in Kun-Lai Summit or a class trainer, who'll grant you entrance to the instance. Upon entering the Proving Grounds, your gear will be scaled down much like it is in Challenge Modes." },
            { type = "h3", text = "Select Your Role and Hone Your Skills as Tank, DPS, or Healer" },
            { type = "p", text = "Within the Proving Grounds, much like in any dungeon, you'll be able to choose the role of tank, DPS, or healer. Once you've decided, you'll be faced with a series of challenges based on the kinds of combat mechanics that role would encounter in a dungeon." },
            { type = "list_item", text = "Tank : You will be tasked with protecting an NPC from oncoming waves of enemies, which will test your tanking skills in various ways. Fear not, though—a friendly NPC will assist by healing you and damaging the enemies.", level = 0 },
            { type = "list_item", text = "Damage : Sometimes you just have to go it alone. You'll melt the usual faces while handling a variety of mechanics, including interrupting heals, chasing down runners, timing cooldowns, avoiding harmful mechanics, and more.", level = 0 },
            { type = "list_item", text = "Healer : Four NPCs will join you to form a full party. It will take a special healing touch to keep your friends alive as you work together to face enemy attacks.", level = 0 },
            { type = "h3", text = "Expand Your Skills And Master All Four Difficulty Modes in Proving Grounds" },
            { type = "p", text = "Proving Grounds will be available in four different modes: Bronze, Silver, Gold, and Endless. Each mode allows you the opportunity to test your mettle and learn a bit more about your role by putting you in the thick of a grouping experience. You'll have to beat each one (beginning with Bronze) to take on the next mode. Once you've beaten Gold, you'll unlock Endless and be truly prepared to astound and amaze your friends with your prowess." },
            { type = "p", text = "In Endless, you'll push yourself to the limits and see just how long you can survive as each wave of foes becomes increasingly difficult to withstand. The longer you survive Endless, the higher your score, and the system will track your progress so you can see just how well you've done." },
            { type = "h3", text = "Face a Sea of Endless Challenges to Improve Your Skills" },
            { type = "p", text = "Re-enter the Proving Grounds as much as you want as you work to improve your skills, earn Achievements, and claim some bragging rights when you survive longer than any of your friends. It's just a quick chat with the NPC, and you're quickly back in action." },
            { type = "p", text = "There's no need to worry about death or taking durability damage. Food and flasks will last their full duration, but leave your potions at home— you won't be able to use them here. You'll also have access to various amenities within the Proving Ground, such as Vendors, Soulwells, repairs, and Reforgers." },
            { type = "p", text = "Now, sharpen those blades, enchant that new robe, and get ready to brave the Proving Grounds." },
            { type = "hr" },
            { type = "p", text = "Steel your resolve, prepare your allies, and step into the final chapter of the Pandaren campaign. The fate of Azeroth awaits on the Timeless Isle, and within the walls of Orgrimmar." },
            { type = "p", text = "Lok’tar ogar!" },
            },
        },
        ["2026-06-03-mists-of-pandaria-classic-siege-of-orgrimmar-raid-unlocks-4-june-e4378431a3"] = {
            id = "2026-06-03-mists-of-pandaria-classic-siege-of-orgrimmar-raid-unlocks-4-june-e4378431a3",
            post_key = "e4378431a3",
            title = "Mists of Pandaria Classic: Siege of Orgrimmar Raid Unlocks 4 June",
            category = "General Discussion (EU)",
            timestamp = 1780498913,
            url = "https://eu.forums.blizzard.com/en/wow/t/620675/1",
            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-03-mists-of-pandaria-classic-siege-of-orgrimmar-raid-unlocks-4-june-e4378431a3\\image-1.jpg" },
            { type = "p", text = "Garrosh Hellscream’s arrogance has brought ruin to the Vale of Eternal Blossoms. Champions of the Alliance and the Horde must march on his capital and bring the ruthless Warchief’s reign to an end." },
            { type = "p", text = "View Full Article" },
            },
        },
        ["2026-06-03-retail-transmog-system-with-no-warning-96fc8f680e"] = {
            id = "2026-06-03-retail-transmog-system-with-no-warning-96fc8f680e",
            post_key = "96fc8f680e",
            title = "Retail transmog system with no warning?",
            category = "Wrath of the Lich King Classic Discussion (US)",
            timestamp = 1780463872,
            url = "https://us.forums.blizzard.com/en/wow/t/2312317/1",
            content = {
            { type = "p", text = "Why was this not even on the PTR? Saving transmog sets in this new system costs over 3x as much in most cases. Just checked and it was 1480g to save 1 set. I’m looking at 10s of thousands of gold to interact with this system on my characters (which all have multiple sets). I get that the system allows you to save them all and change to them at will, but that amount of gold in MoP compared to retail is actually unacceptable" },
            },
        },
        ["2026-06-03-hotfixes-june-2-2026-309280ef2c"] = {
            id = "2026-06-03-hotfixes-june-2-2026-309280ef2c",
            post_key = "309280ef2c",
            title = "Hotfixes: June 2, 2026",
            category = "Blogs (US)",
            timestamp = 1780454754,
            url = "https://news.blizzard.com/en-us/article/24276957/hotfixes-may-26-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "June 2, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Resolved an issue causing Unholy Aura and Forbidden Ritual to be canceled earlier than expected.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue with the Darkmoon Dominion: Blood trinket proccing for multiple stats if they're all equally the lowest stat.", level = 0 },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Death Knight", level = 1 },
            { type = "list_item", text = "Blood", level = 2 },
            { type = "list_item", text = "Bloodworms again have avoidance of area-of-effect spells.", level = 3 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Following an Arena match, the user interface now displays the pre-match Matchmaking Ratings (MMR) for each team.", level = 1 },
            { type = "dev_note", text = "Our goal is to provide more information, so that players can better contextualize their changing MMR.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 26, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "dev_note", text = "Aldrachi Reaver performance has been below its alternative Hero Talent options, so we’re buffing some of its effects to reduce the disparity.", level = 1 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "Death Sweep damage increased by 10%.", level = 2 },
            { type = "dev_note", text = "This resolves an issue from a previous update where Blade Dance damage was increased, but Death Sweep’s damage was not correctly updated to match. The base damage of Death Sweep is intended to be 30% more than that of Blade Dance.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Reaver’s Glaive damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Warblade’s Hunger damage increased by 55%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Wounded Quarry now deals 30% of Physical damage to the target of your Reaver’s Mark (was 25%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Aldrachi Reaver: Reaver’s Glaive damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Warblade’s Hunger damage increased by 55%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Wounded Quarry now deals 25% of Physical damage to the target of your Reaver’s Mark (was 20%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "All damage dealt increased by 4%.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "In addition to an overall damage buff, we’d like to get Sunfury’s damage closer to Spellslinger’s.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 5%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Arcane Missiles damage increased by 10%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Sunfury: Burden of Power - Arcane Blast damage bonus increased to 30% (was 25%). Arcane Pulse damage bonus increased to 20% (was 15%).", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "These changes are intended to increase Fire’s single target damage. The value of the increase should be comparable for all Hero Talent options.", level = 2 },
            { type = "list_item", text = "Pyroblast damage increased by 8%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Frostfire: Frostfire Bolt damage increased by 5%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "dev_note", text = "Frostfire performance is farther behind Spellslinger than we’re happy with, so we’re boosting a number of its talents to increase their single target and AOE damage.", level = 2 },
            { type = "list_item", text = "Frostfire: Frostfire Bolt damage increased by 5%. Does not apply to PvP", level = 2 },
            { type = "list_item", text = "Frostfire: Duality - Pyroblast damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Frostfire: Dualcasting Adept - Shatter damage bonus increased to 40% (was 15%).", level = 2 },
            { type = "list_item", text = "Frostfire: Heat Sink - Flurry damage bonus increased to 25% (was 10%).", level = 2 },
            { type = "list_item", text = "Frostfire: Blast Radius - Comet Storm damage bonus increased to 50% (was 20%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "Herald of the Sun has been trailing behind Templar in overall throughput. To improve its output, we’re extending its effective damage window by granting an additional Dawnlight charge. We’re also aiming to further improve its AoE performance by increasing the duration extension provided by Divine Storm.", level = 2 },
            { type = "list_item", text = "Wake of Ashes now causes the next 3 Holy Power spending abilities to apply a Dawnlight (was 2).", level = 2 },
            { type = "list_item", text = "Endless Gleam now extends Dawnlight’s duration by an additional 0.5 seconds when Divine Storm strikes at least 2 Dawnlights (was 0.3 seconds).", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "We’re reducing the mana costs of some core spell casts so Holy Priest can feel more comfortable casting Prayer of Healing and Flash Heal, particularly in raid settings.", level = 2 },
            { type = "list_item", text = "Flash Heal mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Benediction mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Prayer of Mending mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Prayer of Healing mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "dev_note", text = "Deathstalker damage is below the other Hero Talent options for most content and damage profiles, especially for Assassination, and to the least degree for Subtlety single target output. Changes are targeted at improving Deathstalker’s total performance compared to each specialization’s alternative.", level = 1 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "Deathstalker: Deathstalker’s Mark damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Clear the Witnesses now increases Fan of Knives damage by 60% (was 40%).", level = 2 },
            { type = "list_item", text = "Deathstalker: Hunt Them Down damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Corrupt the Blood now increases Rupture damage by 20% (was 10%).", level = 2 },
            { type = "list_item", text = "Deathstalker: Darkest Night effect now increases Envenom damage by 35% (was 30%).", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "Deathstalker: Deathstalker’s Mark damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Clear the Witnesses now increases Shuriken Storm damage by 60% (was 40%).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "list_item", text = "Farseer: Ancestral Spirits from the Farseer Hero Talent tree now benefit from the critical damage increase of the Elemental Fury talent.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "We’re adjusting the mana costs of some of Restoration Shaman’s basic spell casts to give them more room to spend mana on things like Chain Heal particularly in raid settings.", level = 2 },
            { type = "list_item", text = "The mana cost of Chain Heal, Healing Wave, and Riptide has been reduced by 5%.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "These change aim to improve Colossus’ performance in single target and Mountain Thane’s performance in AOE relative to other Hero Talent options.", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Colossus: Practiced Strikes - Mortal Strike and Slam damage increased by 25% (was 15%). Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Colossus: Practiced Strikes - Shield Slam damage increased by 25% (was 15%). Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%. Does not apply to PvP.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "San’layn: Vampiric Strike damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "Elune’s Chosen: Lunar Calling now increases Starfire damage by an additional 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "Druid of the Claw: Ravage damage increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "dev_note", text = "Preservation has pulled ahead of the other healers partially due to their ability to withstand crowd control but also due to their raw healing output. We’re reducing some of their throughput capabilities and also the uptime on Nullifying Shroud to bring them in line.", level = 2 },
            { type = "list_item", text = "All healing reduced by 5% in PvP combat.", level = 2 },
            { type = "list_item", text = "Nullifying Shroud duration reduced to 3 seconds (was 4 seconds).", level = 2 },
            { type = "list_item", text = "Dream Breath instant healing reduced by 17% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "dev_note", text = "Survival has a strong burst window with Takedown, but outside of that, they are lacking. We’d like to reduce the heavy burst of Takedown and redistribute that power to compensate.", level = 2 },
            { type = "list_item", text = "Takedown damage reduced by 25% in PvP.", level = 2 },
            { type = "list_item", text = "Damage of all spells and abilities increased by 6% in PvP.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "We’d like to increase Fire’s steady state damage by adjusting Fireball to reward casting, and Meteor has been harder to justify picking up than we would like in PvP.", level = 2 },
            { type = "list_item", text = "Fireball and Frostfire Bolt damage increased by 35% in PvP combat.", level = 2 },
            { type = "list_item", text = "Meteor direct damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "Holy Light’s mana cost is more restrictive in PvP than intended, so we’re adjusting Divine Favor to make its use less punishing long-term. Divine Favor now reduces the mana cost of Holy Light by 30% (was 10%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Denounce to not scale its damage with level or with buffs such as Avenging Wrath. This is about a 90% increase to its baseline output.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection Paladin’s damage capabilities have been higher than healthy for a spec with its utility.", level = 2 },
            { type = "list_item", text = "All damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "We’re adjusting Divine Exaction’s effectiveness to reduce Retribution’s burst window.", level = 2 },
            { type = "list_item", text = "Templar: Divine Exaction down to 75% (was 150%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "We’re reducing the mana cost of a few core spells for Holy Priest this week (see PvE changes for details) which is intended to help with healing in longer engagements. Additionally, Archon has felt weak compared to Oracle, so we’re targeting a buff to Halo to improve its viability.", level = 2 },
            { type = "list_item", text = "Archon: Halo damage and healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "We feel Voidweaver is in a good position in PvP. Archon’s pressure is lacking in comparison, so we’re targeting some of its spells to improve its output.", level = 2 },
            { type = "list_item", text = "Archon: Halo damage and healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Archon: Mind Flay Insanity damage increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "dev_note", text = "Elemental is often relying on Ascendance for kills due to its high burst potential. These changes are intended to increase overall pressure while reducing reliance on cooldowns to score skills.", level = 2 },
            { type = "list_item", text = "Bloodlust and Heroism from Shamanism now increases haste by 15% (was 20%)", level = 2 },
            { type = "list_item", text = "Ascendance now increases Elemental Overload damage by 10% in PvP Combat (was 25%).", level = 2 },
            { type = "list_item", text = "Lava Burst damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Lightning Bolt damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "Enhancement burst has been hard to react to during cooldowns due to a Maelstrom Weapon bug we’re fixing. In addition, we’re toning down the haste gained from Shamanism to reduce the cooldown pressure from Shaman DPS specializations.", level = 2 },
            { type = "list_item", text = "Bloodlust and Heroism from Shamanism now increases haste by 15% (was 20%) in PvP.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Malestrom Weapon spenders from Thorim’s Invocation during Doom Winds to deal more damage than intended.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "dev_note", text = "Hellcaller has underperformed compared to Soul Harvester and we would like to shrink that gap.", level = 2 },
            { type = "list_item", text = "Hellcaller: Blackened Soul damage increased by 35% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hellcaller: Wither damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hellcaller: Mark of Xavius now causes Blackened Soul to deal 4% increased damage per stack of Wither in PvP combat (was 2%).", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "dev_note", text = "For Demonology and Destruction, we’re pulling back on some of the previous reductions to Conflagrate and Ruination as they were proving to be a little heavy handed. We’re also bringing up the damage of core casts like Incinerate and Hand of Gul’dan to reward Warlocks more for successful casts.", level = 2 },
            { type = "list_item", text = "Hand of Gul’dan damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Diabolist: Ruination damage increased by 100% in PvP combat.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Incinerate damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Conflagrate damage increased by 60% in PvP combat.", level = 2 },
            { type = "list_item", text = "Diabolist: Ruination damage increased by 100% in PvP combat.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "Berserker Roar’s duration has been overly disruptive. Decreasing it should open up more options when deciding how to handle its effect.", level = 1 },
            { type = "list_item", text = "Berserker Roar’s duration reduced to 5 seconds (was 10 seconds).", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "dev_note", text = "Arms’ overall pressure output has been slightly higher than we would like, so we’re tweaking their damage down to land them in a healthier spot.", level = 2 },
            { type = "list_item", text = "All damage reduced by 3% in PvP combat.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 22, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
