            { type = "list_item", text = "Corrected an issue where the Jet Stream talent would not remove snare effects from allies who enter your Wind Rush Totem's area.", level = 1 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Corrected an issue where the initial healing from dropping a Stormstream Totem was not affected by Mastery: Deep Healing.", level = 2 },
