            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-28-take-a-midsummer-stroll-over-to-the-june-trading-post-cabda6eb75\\image-1.jpg" },
