            { type = "dev_note", text = "Restoration shamans were intended to gain a 30% damage increase with the release of patch 12.0.5, but an error resulted in them gaining about half of that amount. This 12% increase brings them up to a total of +30% damage when compared to before patch 12.0.5.", level = 2 },
