            { type = "list_item", text = "Trickster: Fixed an issue that caused Cloud Cover's effect to cost 30 Energy to activate.", level = 1 },
            { type = "list_item", text = "Trickster: Cloud Cover's visual effect is now only visible to the caster in all circumstances.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Jinx would not function if Foul Mouth was not talented.", level = 2 },
